    private void downloadAndApplyThemeVariant(final ThemeDownloader.CatalogEntry entry,
                                              final ThemeDownloader.ThemeVariant variant) {
        if (layoutLoadingOverlay != null) layoutLoadingOverlay.setVisibility(View.VISIBLE);
        final int gen = themeDownloadGen;
        ThemeDownloader.clearCancel();

        new Thread(new Runnable() {
            @Override
            public void run() {
                try {
                    final String installFolder = ThemeDownloader.resolvedInstallFolder(entry, variant);
                    if (!variant.isComplete(entry.name)) {
                        ThemeDownloader.downloadThemeVariant(entry, variant,
                                new ThemeDownloader.ProgressListener() {
                                    @Override
                                    public void onProgress(final int done, final int total,
                                                           final String fileName) {
                                        runOnUiThreadSafe(new Runnable() {
                                            @Override
                                            public void run() {
                                                if (isFinishing()) return;
                                                setLoadingOverlayText("Downloading " + variant.displayName(entry.name)
                                                        + "\n" + done + " / " + total);
                                            }
                                        });
                                    }
                                });
                    }
                    if (gen != themeDownloadGen) return;
                    ActiveThemeEngine.loadThemes(MainActivity.this);
                    final String toastName = variant.displayName(entry.name);
                    final String path = new File(ThemeManager.PATH_THEMES, installFolder).getAbsolutePath();
                    int index = -1;
                    for (int i = 0; i < ThemeManager.availableThemes.size(); i++) {
                        if (path.equals(ThemeManager.availableThemes.get(i).folderPath)) {
                            index = i;
                            break;
                        }
                    }
                    if (index < 0) throw new Exception("Variant not found after download: " + installFolder);
                    final int themeIndex = index;
                    final ThemeManager.ThemeEntry theme = ThemeManager.availableThemes.get(themeIndex);
                    runOnUiThreadSafe(new Runnable() {
                        @Override
                        public void run() {
                            if (isFinishing() || gen != themeDownloadGen) {
                                if (layoutLoadingOverlay != null) layoutLoadingOverlay.setVisibility(View.GONE);
                                return;
                            }
                            applyThemeWithIntegrityCheck(themeIndex, theme, toastName);
                        }
                    });
                } catch (final Exception e) {
                    ThemeDownloader.dlLogError("downloadAndApplyThemeVariant " + entry.folder, e);
                    runOnUiThreadSafe(new Runnable() {
                        @Override
                        public void run() {
                            if (isFinishing() || gen != themeDownloadGen) return;
                            if (layoutLoadingOverlay != null) layoutLoadingOverlay.setVisibility(View.GONE);
                            Toast.makeText(MainActivity.this, getString(R.string.toast_download_failed), Toast.LENGTH_SHORT).show();
                        }
                    });
                }
            }
        }).start();
    }

    private void downloadAndApplyTheme(final ThemeDownloader.CatalogEntry entry) {
        if (layoutLoadingOverlay != null) layoutLoadingOverlay.setVisibility(View.VISIBLE);
        final int gen = themeDownloadGen;
        ThemeDownloader.clearCancel();

        new Thread(new Runnable() {
            @Override
            public void run() {
                try {
                    if (!entry.isComplete()) {
                        ThemeDownloader.downloadTheme(entry, new ThemeDownloader.ProgressListener() {
                            @Override
                            public void onProgress(final int done, final int total, final String fileName) {
                                runOnUiThreadSafe(new Runnable() {
                                    @Override
                                    public void run() {
                                        if (isFinishing()) return;
                                        setLoadingOverlayText("Downloading " + entry.name + "\n" + done + " / " + total);
                                    }
                                });
                            }
                        });
                    }
                    if (gen != themeDownloadGen) return;
                    ActiveThemeEngine.loadThemes(MainActivity.this);
                    final String installPath = new File(ThemeManager.PATH_THEMES,
                            ThemeDownloader.installedFolderForEntry(entry)).getAbsolutePath();
                    final String themeName = entry.name;
                    int index = -1;
                    for (int i = 0; i < ThemeManager.availableThemes.size(); i++) {
                        if (installPath.equals(ThemeManager.availableThemes.get(i).folderPath)) {
                            index = i;
                            break;
                        }
                    }
                    if (index < 0) throw new Exception("Theme not found after download");
                    final int themeIndex = index;
                    final ThemeManager.ThemeEntry theme = ThemeManager.availableThemes.get(themeIndex);
                    runOnUiThreadSafe(new Runnable() {
                        @Override
                        public void run() {
                            if (isFinishing() || gen != themeDownloadGen) {
                                if (layoutLoadingOverlay != null) layoutLoadingOverlay.setVisibility(View.GONE);
                                return;
                            }
                            applyThemeWithIntegrityCheck(themeIndex, theme, themeName);
                        }
                    });
                } catch (final Exception e) {
                    ThemeDownloader.dlLogError("downloadAndApplyTheme " + entry.folder, e);
                    runOnUiThreadSafe(new Runnable() {
                        @Override
                        public void run() {
                            if (isFinishing() || gen != themeDownloadGen) return;
                            if (layoutLoadingOverlay != null) layoutLoadingOverlay.setVisibility(View.GONE);
                            Toast.makeText(MainActivity.this, getString(R.string.toast_download_failed), Toast.LENGTH_SHORT).show();
                        }
                    });
                }
            }
        }).start();
    }

    /** ponytail: on apply, repair missing assets from catalog when Wi-Fi is up */
    private void applyThemeWithIntegrityCheck(final int index, final ThemeManager.ThemeEntry theme,
                                              final String toastName) {
        if (layoutLoadingOverlay != null) layoutLoadingOverlay.setVisibility(View.VISIBLE);
        if (ActiveThemeEngine.isJjMode()) {
            ActiveThemeEngine.setJjMode(this, false);
        }

        new Thread(new Runnable() {
            @Override
            public void run() {
                int resolvedIndex = index;
                ThemeManager.ThemeEntry resolvedTheme = theme;
                try {
                    if (ThemeManager.isBuiltInDefault(theme)) {
                        ThemeManager.ensureBundledDefault(MainActivity.this);
                        ActiveThemeEngine.loadThemes(MainActivity.this);
                        resolvedIndex = ThemeManager.findBuiltInDefaultIndex();
                        if (resolvedIndex >= 0 && resolvedIndex < ThemeManager.availableThemes.size()) {
                            resolvedTheme = ThemeManager.availableThemes.get(resolvedIndex);
                        }
                    } else if (hasInternetConnection()) {
                        java.util.Set<String> missing = ThemeDownloader.missingAssets(theme.folderName);
                        if (!missing.isEmpty()) {
                            ThemeDownloader.repairThemeFolderIfInCatalog(theme.folderName, null);
                        }
                    }
                } catch (Exception e) {
                    ThemeDownloader.dlLogError("integrity repair " + theme.folderName, e);
                    android.util.Log.w("ThemeDownloader", "integrity repair: " + e.getMessage());
                }
                final int applyIndex = resolvedIndex;
                final ThemeManager.ThemeEntry applyTheme = resolvedTheme;
                final String appliedName = toastName != null ? toastName
                        : (applyTheme != null ? applyTheme.name : null);
                ThemeManager.cacheActiveTheme(MainActivity.this);
                ThemeManager.preferInternalCacheForActiveTheme(MainActivity.this);
                final String persistPath = ThemeManager.persistPathForTheme(applyTheme, MainActivity.this);
                runOnUiThreadSafe(new Runnable() {
                    @Override
                    public void run() {
                        if (isFinishing()) return;
                        if (layoutLoadingOverlay != null) layoutLoadingOverlay.setVisibility(View.GONE);
                        if (applyIndex < 0 || applyTheme == null) return;
                        final ViewGroup root = (ViewGroup) findViewById(android.R.id.content);
                        if (themedContextMenu != null && root != null && appliedName != null) {
                            themedContextMenu.showInstallStatusOverlay(root,
                                    getString(R.string.theme_applying, appliedName), "");
                        }
                        ThemeManager.setThemeIndex(applyIndex);
                        try {
                            SharedPreferences.Editor ed = prefs.edit()
                                    .putInt("app_theme_index", applyIndex)
                                    .putString("app_theme_path", persistPath)
                                    .putBoolean("reboot_to_theme", true);
                            if (ThemeManager.hasThemeWallpaper(applyTheme)) {
                                ed.putString("background_mode", BG_MODE_THEME);
                            }
                            ed.commit();
                        } catch (Exception ignored) {}
                        if (root != null) {
                            root.post(new Runnable() {
                                @Override
                                public void run() {
                                    if (!isFinishing()) recreate();
                                }
                            });
                        } else {
                            recreate();
                        }
                    }
                });
            }
        }).start();
    }

    private boolean isWifiConnected() {
        try {
            WifiManager wm = (WifiManager) getApplicationContext().getSystemService(WIFI_SERVICE);
            if (wm == null || !wm.isWifiEnabled()) return false;
            android.net.wifi.WifiInfo info = wm.getConnectionInfo();
            return info != null && info.getNetworkId() != -1;
        } catch (Exception e) {
            return false;
        }
    }

    private boolean hasInternetConnection() {
        return ConnectivityHelper.isOnline(this);
    }

    private boolean requireInternet(int toastResId) {
        if (hasInternetConnection()) return true;
        Toast.makeText(this, getString(toastResId), Toast.LENGTH_LONG).show();
        return false;
    }

    /** App cache for Reach/Deezer/podcast stream temps (may use SD when internal is full). */
    private File streamAppCacheRoot() {
        return StreamCacheRoot.resolve(getApplicationContext());
    }

    /** Debug Menu — Soulseek/Deezer download error toasts (success toasts stay visible). */
    private boolean shouldShowDownloadErrorToasts() {
        return prefs != null && prefs.getBoolean(PREF_DEBUG_SHOW_ERROR_TOASTS, false);
    }

    private void toastReachDownloadError(CharSequence message) {
        if (!shouldShowDownloadErrorToasts() || message == null || message.length() == 0) return;
        Toast.makeText(this, message, Toast.LENGTH_LONG).show();
    }

    private void toastStreamDownloadWarning(CharSequence message) {
        toastReachDownloadError(message);
    }

    private void onNetworkConnectivityChanged() {
        refreshConnectivityGatedMenus();
    }

    private void refreshConnectivityGatedMenus() {
        scheduleConnectivityGatedMenusRefresh();
    }

    private void scheduleConnectivityGatedMenusRefresh() {
        connectivityUiDebounceHandler.removeCallbacks(connectivityUiDebounceRunnable);
        connectivityUiDebounceHandler.postDelayed(connectivityUiDebounceRunnable, CONNECTIVITY_UI_DEBOUNCE_MS);
    }

    private void refreshConnectivityGatedMenusNow() {
        if (currentScreenState == STATE_MENU) {
            buildHomeMenu();
        } else if (currentScreenState == STATE_MORE) {
            buildMoreMenuUI();
        } else if (currentScreenState == STATE_SETTINGS && settingsSubScreenKey == null) {
            buildSettingsUI();
        }
        if (currentScreenState == STATE_SETTINGS && SettingsScreens.THEMES.equals(settingsSubScreenKey)) {
            if (themeBrowserMode == THEME_BROWSER_MAIN || themeBrowserMode == THEME_BROWSER_GET_MORE) {
                rebuildThemeBrowserRows();
                refreshThemeBrowserList();
            }
        }
        if (currentScreenState == STATE_BROWSER && currentBrowserMode == BROWSER_ROOT && !isPickingBackground) {
            buildFileBrowserUI();
        }
    }

    private void onWifiConnectivityChanged() {
        refreshConnectivityGatedMenus();
        if (hasInternetConnection() && soulseekReachEnabled) {
            SolarDiagnosticReporter.onReachInternetAvailable(this, prefs);
        }
        scheduleSoulseekSharePolicyRefresh();
    }

    private void scheduleSoulseekSharePolicyRefresh() {
        soulseekPolicyDebounceHandler.removeCallbacks(soulseekPolicyDebounceRunnable);
        soulseekPolicyDebounceHandler.postDelayed(soulseekPolicyDebounceRunnable,
                SOULSEEK_POLICY_DEBOUNCE_MS);
    }

    /** ponytail: after 15 min asleep off-charger, drop Wi-Fi unless transfers need it. */
    private void scheduleWifiSleepOff() {
        soulseekUiHandler.removeCallbacks(wifiSleepOffRunnable);
        if (!isWifiSleepPowerOffEnabled()) return;
        if (!isScreenSleeping || soulseekCharging) return;
        soulseekUiHandler.postDelayed(wifiSleepOffRunnable, WIFI_SLEEP_OFF_MS);
    }

    private boolean isWifiSleepPowerOffEnabled() {
        return prefs != null && prefs.getBoolean(WifiSleepPolicy.PREF_ENABLED, true);
    }

    private void cancelWifiSleepOff() {
        soulseekUiHandler.removeCallbacks(wifiSleepOffRunnable);
        soulseekScreenSleepArmed = false;
    }

    /** Re-enable Wi-Fi after sleep policy turned it off — screen on or charger plugged in. */
    private void maybeRestoreWifiAfterSleepPolicy() {
        boolean persisted = prefs != null
                && prefs.getBoolean(WifiSleepPolicy.PREF_DISABLED_BY_POLICY, false);
        if (!WifiSleepPolicy.shouldRestore(wifiDisabledBySleepPolicy, persisted)) return;
        wifiDisabledBySleepPolicy = false;
        if (prefs != null) {
            prefs.edit().putBoolean(WifiSleepPolicy.PREF_DISABLED_BY_POLICY, false).commit();
        }
        try {
            WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
            if (wm != null && !wm.isWifiEnabled()) {
                wm.setWifiEnabled(true);
                triggerAutoReconnect();
            }
        } catch (Exception ignored) {}
    }

    /** Silent Wi-Fi off for sleep policy — no toast while screen is off. */
    private void tryWifiSleepPowerOff() {
        if (!isWifiSleepPowerOffEnabled()) return;
        if (!isScreenSleeping || soulseekCharging) return;
        WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
        if (wm == null || !wm.isWifiEnabled()) return;
        if (wifiSleepBlockedByActiveUse()) {
            // ponytail: retry while playback / transfers / upload server still need the radio.
            soulseekUiHandler.removeCallbacks(wifiSleepOffRunnable);
            soulseekUiHandler.postDelayed(wifiSleepOffRunnable, 60_000L);
            return;
        }
        wifiContextPendingEnable = false;
        wifiContextPendingDisable = true;
        cancelWifiContextScanFollowUps();
        wm.setWifiEnabled(false);
        wifiDisabledBySleepPolicy = true;
        if (prefs != null) {
            prefs.edit().putBoolean(WifiSleepPolicy.PREF_DISABLED_BY_POLICY, true).commit();
        }
        // #region agent log
        try {
            org.json.JSONObject d = soulseekSleepDecisionSnapshot();
            d.put("wifiWasEnabled", true);
            DebugSessionLog.log("MainActivity.tryWifiSleepPowerOff", "wifi sleep off", "H-WIFI", d);
        } catch (Exception ignored) {}
        // #endregion
    }

    /** Real transfers only — not {@link SoulseekClient#isBusy()} policy keep-alive. */
    private boolean shouldKeepSoulseekAwakeForTransfers() {
        if (hasActiveReachDownload() || reachDownloadInProgress()) return true;
        if (isDeezerStreamDownloadInProgress()) return true;
        if (reachPartialPlaybackStarted) return true;
        if (soulseekSearchInProgress) return true;
        if (soulseekClient != null) {
            if (soulseekClient.isTransferActive()) return true;
            if (soulseekClient.isUploadInProgress()) return true;
            if (soulseekClient.isSearchActive()) return true;
        }
        return false;
    }

    private boolean shouldSoulseekSleepForScreen() {
        return soulseekScreenSleepArmed && isScreenSleeping && !soulseekCharging
                && !shouldKeepSoulseekAwakeForTransfers();
    }

    private void triggerAutoReconnect() {
        try {
            WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
            if (wm != null && wm.isWifiEnabled()) {
                wm.reconnect();
            }
            BluetoothAdapter ba = BluetoothAdapter.getDefaultAdapter();
            if (ba != null && ba.isEnabled()) {
                java.util.Set<BluetoothDevice> pairedDevices = ba.getBondedDevices();
            }
        } catch (Exception e) {
        }
    }

    private void toggleWebServer() {
        if (isServerRunning) {
            stopWebServer();
        } else {
            startWebServerIfNeeded();
        }
    }

    private void startWebServerIfNeeded() {
        if (isServerRunning) return;
        if (!ConnectivityHelper.hasLocalNetwork(this)) {
            Toast.makeText(this, getString(R.string.toast_network_required), Toast.LENGTH_SHORT).show();
            return;
        }
        webServer = new SolarWebServer(getApplicationContext(), rootFolder);
        webServer.start();
        isServerRunning = true;
        android.util.Log.i("DeezerDbg", "webserver started ip=" + webServer.getLocalIpAddress());
    }

    private void stopWebServer() {
        if (webServer != null) webServer.stopServer();
        isServerRunning = false;
    }

    private void updateWebServerUI() {
        if (currentScreenState == STATE_DEEZER_SETUP) {
            updateDeezerSetupUI();
            return;
        }
        if (isServerRunning) {
            tvServerStatus.setText(getString(R.string.webserver_running));
            ThemeManager.applyThemedTextStyle(tvServerStatus, ThemeManager.getItemTextColorNormal());
            tvServerIp.setText("http://" + webServer.getLocalIpAddress() + ":8080");
            ThemeManager.applyThemedTextStyle(tvServerIp, ThemeManager.getItemTextColorNormal());
            btnServerToggle.setText(getString(R.string.webserver_stop));
        } else {
            tvServerStatus.setText(getString(R.string.webserver_stopped));
            styleSecondaryLabel(tvServerStatus);
            tvServerIp.setText("http://---.---.---.---:8080");
            styleSecondaryLabel(tvServerIp);
            btnServerToggle.setText(getString(R.string.webserver_start));
        }
        if (tvWebserverHint != null) {
            ThemeManager.applyThemedTextStyle(tvWebserverHint, ThemeManager.getHintTextColor());
        }
    }

    private void updateDeezerSetupUI() {
        if (btnServerToggle != null) btnServerToggle.setVisibility(View.GONE);
        if (isServerRunning) {
            tvServerStatus.setText(getString(R.string.deezer_setup_running));
            ThemeManager.applyThemedTextStyle(tvServerStatus, ThemeManager.getItemTextColorNormal());
            String ip = webServer != null ? webServer.getLocalIpAddress() : ConnectivityHelper.localIpv4(this);
            if (ip == null) ip = "---";
            tvServerIp.setText(getString(R.string.deezer_setup_ip_format, ip));
            ThemeManager.applyThemedTextStyle(tvServerIp, ThemeManager.getItemTextColorNormal());
        } else {
            tvServerStatus.setText(getString(R.string.deezer_setup_stopped));
            styleSecondaryLabel(tvServerStatus);
            tvServerIp.setText(getString(R.string.deezer_setup_ip_format, "---"));
            styleSecondaryLabel(tvServerIp);
        }
        if (tvWebserverHint != null) {
            tvWebserverHint.setText(getString(R.string.deezer_setup_hint));
            ThemeManager.applyThemedTextStyle(tvWebserverHint, ThemeManager.getHintTextColor());
        }
    }

    private void startWebServerForDeezerSetup() {
        webServerStartedForDeezerSetup = false;
        if (isServerRunning) return;
        startWebServerIfNeeded();
        webServerStartedForDeezerSetup = isServerRunning;
    }

    private void openDeezerSetupScreen() {
        openDeezerSetupScreen(false);
    }

    private void openDeezerSetupScreen(boolean preserveReturn) {
        if (!ConnectivityHelper.hasLocalNetwork(this)) {
            Toast.makeText(this, getString(R.string.toast_requires_wifi), Toast.LENGTH_SHORT).show();
            return;
        }
        if (preserveReturn) {
            screenBackReturnTo = currentScreenState;
            changeScreen(STATE_DEEZER_SETUP);
        } else {
            openScreenWithReturn(STATE_DEEZER_SETUP);
        }
    }

    private void returnFromDeezerSetup() {
        if (webServerStartedForDeezerSetup && isServerRunning) {
            stopWebServer();
        }
        webServerStartedForDeezerSetup = false;
        returnFromAuxScreen();
    }

    private void updateMainMenuBackground() {
        if (currentScreenState == STATE_MENU) {
            updateScreenBackground(STATE_MENU);
        } else if (currentScreenState == STATE_PLAYER) {
            updateScreenBackground(STATE_PLAYER);
        }
    }

    private Bitmap loadSelectedThemeWallpaper(int screenState) {
        String pick = prefs.getString(PREF_BG_THEME_WALLPAPER, null);
        if (pick != null) {
            Bitmap picked = ThemeManager.loadWallpaperPick(pick);
            if (picked != null) return picked;
        }
        return loadThemeWallpaperForScreen(screenState);
    }

    private boolean hasEffectiveWallpaper() {
        if (BG_MODE_CUSTOM.equals(getBackgroundMode())) {
            return loadCustomBackgroundBitmap() != null;
        }
        String pick = prefs.getString(PREF_BG_THEME_WALLPAPER, null);
        if (pick != null && ThemeManager.loadWallpaperPick(pick) != null) return true;
        return ThemeManager.hasThemeWallpaper();
    }

    private Bitmap loadThemeWallpaperForScreen(int screenState) {
        String prefKey = null;
        if (screenState == STATE_MENU) prefKey = PREF_BG_HOME;
        else if (screenState == STATE_BROWSER) prefKey = PREF_BG_LIBRARY;
        else if (screenState == STATE_SETTINGS) prefKey = PREF_BG_SETTINGS;
        else if (screenState == STATE_PLAYER) prefKey = PREF_BG_NOW_PLAYING;
        if (prefKey != null) {
            String pick = prefs.getString(prefKey, null);
            if (pick != null) {
                Bitmap b = ThemeManager.loadWallpaperPick(pick);
                if (b != null) return b;
            }
        }
        Bitmap wall;
        if (screenState == STATE_MENU) {
            wall = ThemeManager.getWallpaper(true);
            if (wall == null) wall = ThemeManager.getWallpaper(false);
        } else {
            wall = ThemeManager.getWallpaper(false);
            if (wall == null) wall = ThemeManager.getWallpaper(true);
        }
        return wall;
    }

    private Bitmap loadThemeMaskForScreen(int screenState) {
        if (screenState == STATE_MENU) return ThemeManager.getDesktopMask();
        if (screenState == STATE_SETTINGS) return ThemeManager.getSettingMask();
        return null;
    }

    private boolean hasAlbumArtForBlur() {
        return lastAlbumArtBytes != null && lastAlbumArtBytes.length > 0;
    }

    private void applyOverlayBackgrounds() {
        int overlay = hasEffectiveWallpaper()
                ? 0x00000000 : ThemeManager.getOverlayBackgroundColor();
        if (layoutBrowserMode != null) layoutBrowserMode.setBackgroundColor(overlay);
        if (layoutSettingsMode != null) layoutSettingsMode.setBackgroundColor(overlay);
        if (layoutBluetoothMode != null) layoutBluetoothMode.setBackgroundColor(overlay);
        if (layoutWifiMode != null) layoutWifiMode.setBackgroundColor(overlay);
        if (layoutWifiKeyboard != null) layoutWifiKeyboard.setBackgroundColor(overlay);
        if (layoutBrightnessMode != null) layoutBrightnessMode.setBackgroundColor(overlay);
        if (layoutStorageMode != null) layoutStorageMode.setBackgroundColor(overlay);
        if (layoutWebServerMode != null) layoutWebServerMode.setBackgroundColor(overlay);
    }

    private void updateScreenBackground(int screenState) {
        if (ivMainBg == null) return;
        try {
            applyOverlayBackgrounds();
            com.solar.launcher.ui.ScreenBackdropTransition.BackdropSnapshot snap =
                    resolveBackdropSnapshot(screenState);
            applyBackdropSnapshot(snap, ivMainBg, ivScreenMask);
            if (screenState == STATE_PLAYER) {
                bindPlayerBlurBackdrop();
            }
            refreshRightPanePreviewLayout();
        } catch (Throwable t) {
            ivMainBg.setImageResource(R.drawable.default_back);
            applyScreenMask(null);
            refreshRightPanePreviewLayout();
        }
    }

    /** Build cropped wall + mask for backdrop transition or static apply. */
    private com.solar.launcher.ui.ScreenBackdropTransition.BackdropSnapshot resolveBackdropSnapshot(
            int screenState) {
        Bitmap wall = null;
        Bitmap mask = null;
        boolean defaultWall = false;
        String mode = getBackgroundMode();

        if (BG_MODE_CUSTOM.equals(mode)) {
            wall = loadCustomBackgroundBitmap();
        } else {
            wall = loadSelectedThemeWallpaper(screenState);
            mask = loadThemeMaskForScreen(screenState);
        }

        if (isFullWidthMenus || settingsBrowseFullWidth) {
            mask = null;
        }
        if (screenState == STATE_MENU && anyHomeWidgetActive()) {
            mask = null;
        }

        Bitmap croppedWall = null;
        Bitmap croppedMask = null;
        if (wall != null && screenWidthPx > 0 && screenHeightPx > 0) {
            croppedWall = ThemeManager.centerCropBitmap(wall, screenWidthPx, screenHeightPx);
        } else if (screenState != STATE_PLAYER) {
            defaultWall = true;
        }
        if (mask != null && screenWidthPx > 0 && screenHeightPx > 0) {
            croppedMask = ThemeManager.centerCropBitmap(mask, screenWidthPx, screenHeightPx);
        }
        return new com.solar.launcher.ui.ScreenBackdropTransition.BackdropSnapshot(
                screenState, croppedWall, croppedMask, defaultWall);
    }

    private void applyBackdropSnapshot(
            com.solar.launcher.ui.ScreenBackdropTransition.BackdropSnapshot snap,
            ImageView wallView, ImageView maskView) {
        if (snap == null || wallView == null) return;
        if (snap.wall != null) {
            wallView.setImageBitmap(snap.wall);
        } else if (snap.defaultWall) {
            wallView.setImageResource(R.drawable.default_back);
        } else {
            wallView.setImageResource(R.drawable.default_back);
        }
        applyScreenMaskToView(maskView, snap != null ? snap.mask : null);
    }

    private void applyScreenMask(Bitmap mask) {
        applyScreenMaskToView(ivScreenMask, mask);
    }

    private void applyScreenMaskToView(ImageView maskView, Bitmap mask) {
        if (maskView == null) return;
        if (mask != null) {
            if (maskView == ivScreenMask && screenWidthPx > 0 && screenHeightPx > 0) {
                maskView.setImageBitmap(ThemeManager.centerCropBitmap(mask, screenWidthPx, screenHeightPx));
            } else {
                maskView.setImageBitmap(mask);
            }
            maskView.setVisibility(View.VISIBLE);
        } else {
            maskView.setVisibility(View.GONE);
        }
    }
    private void bindPlayerBlurBackdrop() {
        if (ivPlayerBgBlur == null) return;
        String mode = getBackgroundMode();
        if (playerAlbumBlurEnabled && hasAlbumArtForBlur()) {
            BitmapFactory.Options optsBg = new BitmapFactory.Options();
            optsBg.inSampleSize = 4;
            Bitmap sourceBg = BitmapFactory.decodeByteArray(
                    lastAlbumArtBytes, 0, lastAlbumArtBytes.length, optsBg);
            if (sourceBg != null) {
                Bitmap blurredBg = applyGaussianBlur(sourceBg);
                ivPlayerBgBlur.setImageBitmap(blurredBg);
                if (sourceBg != blurredBg) sourceBg.recycle();
            }
        } else {
            Bitmap bg = BG_MODE_CUSTOM.equals(mode)
                    ? loadCustomBackgroundBitmap()
                    : loadSelectedThemeWallpaper(STATE_PLAYER);
            if (bg != null) {
                ivPlayerBgBlur.setImageBitmap(
                        ThemeManager.centerCropBitmap(bg, screenWidthPx, screenHeightPx));
            } else {
                ivPlayerBgBlur.setImageResource(0);
            }
        }
    }

    /** Copy live Now Playing blur onto the global outgoing backdrop for slide-down exits. */
    private void bindOutgoingPlayerBackdrop(ImageView wall, ImageView mask) {
        if (wall == null || ivPlayerBgBlur == null) return;
        android.graphics.drawable.Drawable d = ivPlayerBgBlur.getDrawable();
        if (d instanceof android.graphics.drawable.BitmapDrawable) {
            android.graphics.Bitmap bmp =
                    ((android.graphics.drawable.BitmapDrawable) d).getBitmap();
            if (bmp != null) {
                wall.setImageBitmap(bmp);
            }
        } else {
            bindPlayerBlurBackdrop();
            d = ivPlayerBgBlur.getDrawable();
            if (d instanceof android.graphics.drawable.BitmapDrawable) {
                android.graphics.Bitmap bmp =
                        ((android.graphics.drawable.BitmapDrawable) d).getBitmap();
                if (bmp != null) wall.setImageBitmap(bmp);
            }
        }
        if (mask != null) mask.setVisibility(View.GONE);
    }

    private String backdropCacheKey(int screenState) {
        StringBuilder sb = new StringBuilder();
        sb.append(screenState).append('|').append(getBackgroundMode());
        sb.append('|').append(isFullWidthMenus).append('|').append(settingsBrowseFullWidth);
        sb.append('|').append(prefs.getString(PREF_BG_THEME_WALLPAPER, ""));
        if (screenState == STATE_MENU) sb.append('|').append(prefs.getString(PREF_BG_HOME, ""));
        else if (screenState == STATE_BROWSER) sb.append('|').append(prefs.getString(PREF_BG_LIBRARY, ""));
        else if (screenState == STATE_SETTINGS) sb.append('|').append(prefs.getString(PREF_BG_SETTINGS, ""));
        else if (screenState == STATE_PLAYER) sb.append('|').append(prefs.getString(PREF_BG_NOW_PLAYING, ""));
        if (screenState == STATE_PLAYER && playerAlbumBlurEnabled && hasAlbumArtForBlur()) {
            sb.append('|').append(lastAlbumArtBytes.length);
        }
        return sb.toString();
    }

    private final com.solar.launcher.ui.ScreenBackdropTransition.Resolver backdropResolver =
            new com.solar.launcher.ui.ScreenBackdropTransition.Resolver() {
                @Override
                public com.solar.launcher.ui.ScreenBackdropTransition.BackdropSnapshot resolveSnapshot(
                        int screenState) {
                    return resolveBackdropSnapshot(screenState);
                }

                @Override
                public void bindPlayerBlurEarly() {
                    bindPlayerBlurBackdrop();
                }

                @Override
                public void bindOutgoingPlayerBackdrop(ImageView wall, ImageView mask) {
                    MainActivity.this.bindOutgoingPlayerBackdrop(wall, mask);
                }

                @Override
                public int screenWidthPx() {
                    return MainActivity.this.screenWidthPx;
                }

                @Override
                public int screenHeightPx() {
                    return MainActivity.this.screenHeightPx;
                }
            };

    private void prepareTransitionBackdrop(int from, int to) {
        screenBackdropTransition.prepareIncoming(backdropResolver, from, to,
                backdropCacheKey(from), backdropCacheKey(to));
    }

    private void commitTransitionBackdrop(int to) {
        screenBackdropTransition.commit(to, backdropResolver);
        if (to != STATE_PLAYER) {
            syncStaticBackdropAfterTransition(to);
        }
    }

    /** Lightweight overlay refresh after backdrop commit — skips full decode when already bound. */
    private void syncStaticBackdropAfterTransition(int screenState) {
        applyOverlayBackgrounds();
        refreshRightPanePreviewLayout();
    }

    private Bitmap loadCustomBackgroundBitmap() {
        String savedBgPath = prefs.getString("bg_path", null);
        if (savedBgPath == null || savedBgPath.isEmpty()) return null;
        File bgFile = new File(savedBgPath);
        if (!bgFile.exists()) return null;
        BitmapFactory.Options opts = new BitmapFactory.Options();
        opts.inJustDecodeBounds = true;
        BitmapFactory.decodeFile(savedBgPath, opts);
        int scale = 1;
        int maxDim = Math.max(opts.outWidth, opts.outHeight);
        while (maxDim / scale > 800) scale *= 2;
        opts.inJustDecodeBounds = false;
        opts.inSampleSize = scale;
        return BitmapFactory.decodeFile(savedBgPath, opts);
    }

    /** Desktop/setting mask frames the right preview pane — tighten art and hide titles when active. */
    private boolean isHomeDesktopMaskActive() {
        return ivScreenMask != null
                && ivScreenMask.getVisibility() == View.VISIBLE
                && currentScreenState == STATE_MENU
                && !isFullWidthMenus
                && !anyHomeWidgetActive();
    }

    private boolean isSettingsPaneMaskActive() {
        return ivScreenMask != null
                && ivScreenMask.getVisibility() == View.VISIBLE
                && currentScreenState == STATE_SETTINGS
                && !isFullWidthMenus
                && !settingsAboutFullWidth
                && !settingsBrowseFullWidth;
    }

    private void refreshRightPanePreviewLayout() {
        if (isFinishing()) return;
        boolean homeMask = isHomeDesktopMaskActive();
        MenuPreviewLayout.Spec homeSpec = MenuPreviewLayout.homeSpec(this, homeMask);
        if (ivMenuPreview != null && ivMenuPreview.getVisibility() == View.VISIBLE) {
            MenuPreviewLayout.applyImagePreview(ivMenuPreview, homeSpec);
        }
        if (layoutWidgets != null) {
            boolean widgetsVisible = layoutWidgets.getVisibility() == View.VISIBLE;
            MenuPreviewLayout.Spec widgetSpec = MenuPreviewLayout.homeSpec(this, widgetsVisible ? false : homeMask);
            MenuPreviewLayout.applyLinearPreview(layoutWidgets, widgetSpec);
            if (widgetsVisible) {
                MenuPreviewLayout.applyWidgetAlbum(ivWidgetAlbum, layoutWidgets, widgetSpec);
            }
        }
        if (homeMask) {
            if (tvMenuPreviewTitle != null) tvMenuPreviewTitle.setVisibility(View.GONE);
            if (tvMenuPreviewArtist != null) tvMenuPreviewArtist.setVisibility(View.GONE);
        }
        applySettingsPreviewPaneLayout(isSettingsPaneMaskActive());
    }

    private void applySettingsPreviewPaneLayout(boolean maskActive) {
        if (settingsPreviewPane == null || settingsPreviewPane.getVisibility() != View.VISIBLE) return;
        MenuPreviewLayout.Spec spec = MenuPreviewLayout.settingsSpec(this, maskActive);
        MenuPreviewLayout.applySettingsPreviewPane(settingsPreviewPane, ivSettingsPreviewIcon, spec, maskActive, this);
        if (maskActive) {
            if (tvSettingsPreviewTitle != null) tvSettingsPreviewTitle.setVisibility(View.GONE);
            if (settingsPreviewStateScroll != null) settingsPreviewStateScroll.setVisibility(View.GONE);
        }
    }


    // 💡 [추가] 테마 색상과 '둥글기(Radius)'를 혼합해서 버튼의 배경 디자인을 찍어내는 도구
    private android.graphics.drawable.GradientDrawable createButtonBackground(int color) {
        android.graphics.drawable.GradientDrawable shape = new android.graphics.drawable.GradientDrawable();
        shape.setColor(color); // 테마 색상 주입
        // 테마에 설정된 둥글기(Radius) 값 주입 (dp 단위를 픽셀로 변환하여 적용)
        float radius = ThemeManager.getButtonRadius() * getResources().getDisplayMetrics().density;
        shape.setCornerRadius(radius);
        return shape;
    }

    /** ponytail: stock Y1 — home=item rows, settings=menu rows, lists=item rows */
    private void initY1LayoutMetrics() {
        float density = getResources().getDisplayMetrics().density;
        y1RowWidthPx = (int) (getResources().getDimension(R.dimen.y1_menu_width));
        y1RowHeightPx = (int) (getResources().getDimension(R.dimen.y1_menu_item_height));
        y1LibraryRowHeightPx = (int) (getResources().getDimension(R.dimen.y1_library_row_height));
        listRowWidthPx = (int) (getResources().getDimension(R.dimen.y1_screen_width) - 20 * density);
        y1ThemeCoverHeightPx = (int) (getResources().getDimension(R.dimen.y1_theme_cover_height));
        y1BatteryIconHeightPx = (int) (getResources().getDimension(R.dimen.y1_battery_icon_height));
        screenWidthPx = (int) getResources().getDimension(R.dimen.y1_screen_width);
        screenHeightPx = (int) getResources().getDimension(R.dimen.y1_screen_height);
        settingsMenuWidthPx = (int) getResources().getDimension(R.dimen.y1_settings_menu_width);
        menuListHeightPx = (int) getResources().getDimension(R.dimen.y1_menu_height);
    }

    private android.graphics.drawable.Drawable getY1RowBackground(boolean focused, int widthPx, int rowKind) {
        boolean selected = focused;
        android.graphics.drawable.Drawable scaled;
        if (rowKind == Y1_ROW_HOME || rowKind == Y1_ROW_ITEM) {
            scaled = ThemeManager.getItemRowBackgroundScaled(
                    getResources(), selected, widthPx, y1RowHeightPx);
        } else {
            scaled = ThemeManager.getMenuRowBackgroundScaled(
                    getResources(), selected, widthPx, y1RowHeightPx);
        }
        if (scaled != null) return scaled;
        boolean menuRows = rowKind == Y1_ROW_MENU;
        if (!selected && ThemeManager.y1UnselectedRowTransparent(menuRows)) {
            if (rowKind == Y1_ROW_HOME) {
                return new android.graphics.drawable.ColorDrawable(ThemeManager.getListButtonNormalBg());
            }
            return new android.graphics.drawable.ColorDrawable(0x00000000);
        }
        if (selected) return createButtonBackground(ThemeManager.getRowSelectionFillColor());
        return new android.graphics.drawable.ColorDrawable(ThemeManager.getListButtonNormalBg());
    }

    private android.graphics.drawable.Drawable getY1RowBackground(boolean focused, int widthPx) {
        return getY1RowBackground(focused, widthPx, y1RowKindForScreen());
    }

    private int y1ActiveRowWidthPx() {
        if (isFullWidthMenus && screenWidthPx > 0) return screenWidthPx;
        if (currentScreenState == STATE_SETTINGS) {
            if (settingsBrowseFullWidth && screenWidthPx > 0) {
                return screenWidthPx;
            }
            if (soulseekConversationHost != null
                    && soulseekConversationHost.getVisibility() == View.VISIBLE
                    && screenWidthPx > 0) {
                return screenWidthPx;
            }
            return settingsMenuWidthPx > 0 ? settingsMenuWidthPx : y1RowWidthPx;
        }
        if (currentScreenState == STATE_MENU) return y1RowWidthPx;
        return listRowWidthPx;
    }

    private void configureReachListView(ListView list) {
        if (list == null) return;
        Y1ScrollIndicators.applyVerticalListView(list);
        list.setDivider(null);
        list.setSelector(new android.graphics.drawable.ColorDrawable(0));
        list.setItemsCanFocus(true);
        list.setChoiceMode(ListView.CHOICE_MODE_SINGLE);
        list.setDescendantFocusability(ViewGroup.FOCUS_AFTER_DESCENDANTS);
        list.setScrollingCacheEnabled(false);
        // ponytail: smooth scrollbars NPE in View.onDrawScrollBars on API 17 (Y1 Messages inbox).
        list.setSmoothScrollbarEnabled(false);
    }

    private void focusFirstReachBrowseDataRow() {
        if (listReachBrowse == null) return;
        android.widget.ListAdapter ad = listReachBrowse.getAdapter();
        if (ad instanceof ReachInterestsAdapter) {
            ReachInterestsAdapter ia = (ReachInterestsAdapter) ad;
            int first = ia.firstSelectablePosition();
            if (first >= 0) {
                int pos = reachBrowseHeaderOffset() + first;
                FocusScrollHelper.focusListPosition(listReachBrowse, pos);
                return;
            }
        }
        if (ad instanceof ReachInboxAdapter) {
            ReachInboxAdapter ia = (ReachInboxAdapter) ad;
            if (SettingsScreens.SOULSEEK_MESSAGES.equals(settingsSubScreenKey)) {
                focusSoulseekMessagesInbox(ia);
                return;
            }
            if (ia.getDataCount() <= 0) {
                if (!reachBrowseHeaderViews.isEmpty()) {
                    focusReachBrowseHeaderIndex(0);
                    return;
                }
                listReachBrowse.requestFocus();
                return;
            }
        }
        if (ad instanceof ReachUsersAdapter) {
            focusFindReachUsersBrowse((ReachUsersAdapter) ad);
            return;
        }
        if (ad instanceof ReachChatRoomsAdapter) {
            focusReachChatRoomsBrowse((ReachChatRoomsAdapter) ad);
            return;
        }
        if (ad == null || ad.getCount() == 0) {
            if (!reachBrowseHeaderViews.isEmpty()) {
                int headerIdx = 0;
                if (SettingsScreens.SOULSEEK_CHAT_ROOMS.equals(settingsSubScreenKey)
                        && reachBrowseHeaderViews.size() >= 2) {
                    headerIdx = 1;
                }
                focusReachBrowseHeaderIndex(headerIdx);
                return;
            }
            listReachBrowse.requestFocus();
            return;
        }
        int pos = reachBrowseHeaderOffset();
        applyReachBrowseAdapterSelection(pos);
        FocusScrollHelper.focusListPosition(listReachBrowse, pos);
    }

    /** Find other Reach users — focus first directory row with adapter highlight synced. */
    private void focusFindReachUsersBrowse(final ReachUsersAdapter ua) {
        if (listReachBrowse == null || ua == null) return;
        listReachBrowse.setSelectionFromTop(0, 0);
        if (ua.getDataCount() <= 0) {
            if (!reachBrowseHeaderViews.isEmpty()) focusReachBrowseHeaderIndex(0);
            return;
        }
        final int listPos = reachBrowseHeaderOffset();
        listReachBrowse.post(new Runnable() {
            @Override
            public void run() {
                ua.setSelectedPosition(0);
                applyReachBrowseAdapterSelection(listPos);
                FocusScrollHelper.focusListPosition(listReachBrowse, listPos);
            }
        });
    }

    /** Chat rooms search results — sync highlight with first selectable room row. */
    private void focusReachChatRoomsBrowse(final ReachChatRoomsAdapter ca) {
        if (listReachBrowse == null || ca == null) return;
        listReachBrowse.setSelectionFromTop(0, 0);
        if (ca.getDataCount() <= 0) {
            int headerIdx = 0;
            if (SettingsScreens.SOULSEEK_CHAT_ROOMS.equals(settingsSubScreenKey)
                    && reachBrowseHeaderViews.size() >= 2) {
                headerIdx = 1;
            }
            if (!reachBrowseHeaderViews.isEmpty()) focusReachBrowseHeaderIndex(headerIdx);
            return;
        }
        final int listPos = reachBrowseHeaderOffset();
        listReachBrowse.post(new Runnable() {
            @Override
            public void run() {
                ca.setSelectedPosition(0);
                applyReachBrowseAdapterSelection(listPos);
                FocusScrollHelper.focusListPosition(listReachBrowse, listPos);
            }
        });
    }

    /** Messages inbox: first conversation when present, else New message (not Back or status row). */
    private void focusSoulseekMessagesInbox(final ReachInboxAdapter ia) {
        if (listReachBrowse == null || ia == null) return;
        // ponytail: reset scroll — prior Reach browse can leave the list scrolled down off-screen.
        listReachBrowse.setSelectionFromTop(0, 0);
        final int dataCount = ia.getDataCount();
        if (dataCount > 0) {
            final int listPos = reachBrowseHeaderOffset();
            ia.setSelectedPosition(0);
            listReachBrowse.post(new Runnable() {
                @Override
                public void run() {
                    applyReachBrowseAdapterSelection(listPos);
                    FocusScrollHelper.focusListPosition(listReachBrowse, listPos);
                    // #region agent log
                    try {
                        org.json.JSONObject d = new org.json.JSONObject();
                        d.put("mode", "first_peer");
                        d.put("listPos", listPos);
                        d.put("dataCount", dataCount);
                        d.put("selected", listReachBrowse.getSelectedItemPosition());
                        DebugSessionLog.log("MainActivity.focusSoulseekMessagesInbox",
                                "focused", "H-M7", d);
                    } catch (Exception ignored) {}
                    // #endregion
                }
            });
            return;
        }
        final int headerIdx = reachBrowseHeaderViews.size() >= 2 ? 1 : 0;
        listReachBrowse.post(new Runnable() {
            @Override
            public void run() {
                focusReachBrowseHeaderIndex(headerIdx);
                // #region agent log
                try {
                    org.json.JSONObject d = new org.json.JSONObject();
                    d.put("mode", "new_message_header");
                    d.put("headerIdx", headerIdx);
                    d.put("dataCount", dataCount);
                    DebugSessionLog.log("MainActivity.focusSoulseekMessagesInbox",
                            "focused", "H-M7", d);
                } catch (Exception ignored) {}
                // #endregion
            }
        });
    }

    private int indexOfReachBrowseHeader(View v) {
        if (v == null) return -1;
        for (int i = 0; i < reachBrowseHeaderViews.size(); i++) {
            View h = reachBrowseHeaderViews.get(i);
            if (h == v || isViewDescendantOf(v, h)) return i;
        }
        return -1;
    }

    /** Header row for wheel nav — real focus or tracked index when ListView still owns selection. */
    private int reachBrowseActiveHeaderIndex() {
        int idx = indexOfReachBrowseHeader(getCurrentFocus());
        if (idx >= 0) {
            reachBrowseHeaderFocusIdx = idx;
            return idx;
        }
        if (reachBrowseHeaderFocusIdx >= 0 && reachBrowseHeaderFocusIdx < reachBrowseHeaderViews.size()) {
            View h = reachBrowseHeaderViews.get(reachBrowseHeaderFocusIdx);
            if (h != null && (h.hasFocus() || h.isFocused())) return reachBrowseHeaderFocusIdx;
        }
        return -1;
    }

    private boolean focusReachBrowseHeaderIndex(final int idx) {
        if (idx < 0 || idx >= reachBrowseHeaderViews.size()) return false;
        final View h = reachBrowseHeaderViews.get(idx);
        if (h == null || !h.isFocusable()) return false;
        reachBrowseHeaderFocusIdx = idx;
        clearReachBrowseAdapterSelection(listReachBrowse != null ? listReachBrowse.getAdapter() : null);
        if (h.requestFocus()) {
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("headerIdx", idx);
                d.put("focused", true);
                DebugSessionLog.log("MainActivity.focusReachBrowseHeaderIndex",
                        "chrome focus", "H-HEADER", d);
            } catch (Exception ignored) {}
            // #endregion
            return true;
        }
        listReachBrowse.post(new Runnable() {
            @Override
            public void run() {
                h.requestFocus();
            }
        });
        return true;
    }

    private void clearReachBrowseAdapterSelection(android.widget.ListAdapter ad) {
        if (ad instanceof ReachInboxAdapter) {
            ((ReachInboxAdapter) ad).clearSelectedPosition();
        } else if (ad instanceof ReachUsersAdapter) {
            ((ReachUsersAdapter) ad).clearSelectedPosition();
        } else if (ad instanceof ReachChatRoomsAdapter) {
            ((ReachChatRoomsAdapter) ad).setSelectedPosition(-1);
        } else if (ad instanceof ReachUsersAdapter) {
            ((ReachUsersAdapter) ad).setSelectedPosition(-1);
        } else if (ad instanceof ReachInterestsAdapter) {
            ((ReachInterestsAdapter) ad).setSelectedPosition(-1);
        }
    }

    /** List position for wheel nav — prefer adapter highlight index over ListView selection. */
    private int reachBrowseFocusedListPosition(android.widget.ListAdapter ad) {
        int headerCount = reachBrowseHeaderOffset();
        if (ad instanceof ReachInboxAdapter) {
            int sel = ((ReachInboxAdapter) ad).getSelectedPosition();
            if (sel >= 0) return headerCount + sel;
        } else if (ad instanceof ReachChatRoomsAdapter) {
            int sel = ((ReachChatRoomsAdapter) ad).getSelectedPosition();
            if (sel >= 0) return headerCount + sel;
        } else if (ad instanceof ReachUsersAdapter) {
            int sel = ((ReachUsersAdapter) ad).getSelectedPosition();
            if (sel >= 0) return headerCount + sel;
        } else if (ad instanceof ReachInterestsAdapter) {
            int sel = ((ReachInterestsAdapter) ad).getSelectedPosition();
            if (sel >= 0) return headerCount + sel;
        }
        int pos = listReachBrowse != null ? listReachBrowse.getSelectedItemPosition() : -1;
        if (pos >= headerCount) return pos;
        if (listReachBrowse != null) {
            View focus = getCurrentFocus();
            if (focus != null) {
                int idx = listReachBrowse.getPositionForView(focus);
                if (idx != android.widget.AdapterView.INVALID_POSITION && idx >= headerCount) {
                    return idx;
                }
            }
        }
        return headerCount;
    }

    private int conversationRowWidthPx() {
        return messagingRowWidthPx();
    }

    private int messagingRowWidthPx() {
        if (isFullWidthMenus || settingsBrowseFullWidth) {
            return screenWidthPx > 0 ? screenWidthPx : y1ActiveRowWidthPx();
        }
        return settingsMenuWidthPx > 0 ? settingsMenuWidthPx : y1RowWidthPx;
    }

    private static boolean isReachBrowseScreen(String key) {
        return SettingsScreens.SOULSEEK_CHAT_ROOMS.equals(key)
                || SettingsScreens.SOULSEEK_CHAT_ROOM_THREAD.equals(key)
                || SettingsScreens.SOULSEEK_CHAT_ROOM_WALL.equals(key)
                || SettingsScreens.SOULSEEK_MESSAGES.equals(key)
                || SettingsScreens.SOULSEEK_MESSAGES_THREAD.equals(key)
                || SettingsScreens.SOULSEEK_FIND_REACH.equals(key)
                || SettingsScreens.SOULSEEK_FIND_USER.equals(key)
                || SettingsScreens.SOULSEEK_INTERESTS.equals(key)
                || SettingsScreens.SOULSEEK_USER_PROFILE.equals(key);
    }

    /** Debug / Flow / Report toggles use full-width list rows — labels are too long for dual-pane preview. */
    private static boolean isSettingsFullWidthSubScreen(String key) {
        return SettingsScreens.DEBUG.equals(key)
                || SettingsScreens.FLOW.equals(key);
    }

    private void applyReachBrowseLayoutMode() {
        settingsBrowseFullWidth = isReachBrowseScreen(settingsSubScreenKey)
                || isSettingsFullWidthSubScreen(settingsSubScreenKey)
                || currentScreenState == STATE_DEEZER
                || currentScreenState == STATE_SOULSEEK;
        applyFullWidthMenusLayout();
    }

    /** @deprecated use applyReachBrowseLayoutMode */
    private void applyMessagingLayoutMode() {
        applyReachBrowseLayoutMode();
    }

    private void showReachBrowseList(boolean show) {
        if (settingsScrollView != null) {
            settingsScrollView.setVisibility(show ? View.GONE : View.VISIBLE);
        }
        if (reachBrowseHost != null) {
            reachBrowseHost.setVisibility(show ? View.VISIBLE : View.GONE);
        }
        if (listReachBrowse != null && show) {
            listReachBrowse.setDescendantFocusability(ViewGroup.FOCUS_AFTER_DESCENDANTS);
        }
        if (soulseekConversationHost != null && show) {
            soulseekConversationHost.setVisibility(View.GONE);
        }
        if (show) {
            stopSettingsPreviewVerticalMarquee();
            if (settingsPreviewPane != null) {
                settingsPreviewPane.setVisibility(View.GONE);
            }
        } else if (settingsPreviewPane != null && !isFullWidthMenus && !settingsAboutFullWidth
                && !settingsBrowseFullWidth) {
            settingsPreviewPane.setVisibility(View.VISIBLE);
        }
    }

    private void clearReachBrowseList() {
        if (listReachBrowse == null) return;
        listReachBrowse.setAdapter(null);
        int headers = listReachBrowse.getHeaderViewsCount();
        for (int i = headers - 1; i >= 0; i--) {
            listReachBrowse.removeHeaderView(listReachBrowse.getChildAt(i));
        }
        // removeHeaderView needs the actual view reference — track headers instead
    }

    private final java.util.ArrayList<View> reachBrowseHeaderViews = new java.util.ArrayList<View>();
    /** Wheel highlight on fixed chrome rows above the peer list (Back / New message). */
    private int reachBrowseHeaderFocusIdx = -1;
    /** Legacy ListView header host — removed when chrome moved outside the list. */
    private LinearLayout reachBrowseHeaderHost;

    private void resetReachBrowseHeaders() {
        if (listReachBrowse == null) return;
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("adapterAttached", listReachBrowse.getAdapter() != null);
            d.put("headerCount", reachBrowseHeaderViews.size());
            d.put("listHeaderViews", listReachBrowse.getHeaderViewsCount());
            DebugSessionLog.log("MainActivity.resetReachBrowseHeaders", "before reset", "H-M1", d);
        } catch (Exception ignored) {}
        // #endregion
        listReachBrowse.setAdapter(null);
        listReachBrowse.setOnItemSelectedListener(null);
        if (reachBrowseHeaderHost != null) {
            try {
                listReachBrowse.removeHeaderView(reachBrowseHeaderHost);
            } catch (Exception ignored) {}
            reachBrowseHeaderHost = null;
        }
        if (reachBrowseChromeHost != null) {
            reachBrowseChromeHost.removeAllViews();
        }
        reachBrowseHeaderViews.clear();
        reachBrowseHeaderFocusIdx = -1;
    }

    private void ensureReachBrowseHeaderHost() {
        if (reachBrowseChromeHost == null) return;
        // Fixed chrome host is declared in activity_main.xml — no ListView header view.
    }

    private void addReachBrowseHeader(View header) {
        if (header == null) return;
        ensureReachBrowseHeaderHost();
        if (reachBrowseChromeHost == null) return;
        header.setLayoutParams(new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT));
        reachBrowseChromeHost.addView(header);
        reachBrowseHeaderViews.add(header);
    }

    /** Chrome rows sit outside the ListView — adapter index equals list position. */
    private int reachBrowseHeaderOffset() {
        return 0;
    }

    private int reachBrowseAdapterIndex(int listPosition) {
        return listPosition - reachBrowseHeaderOffset();
    }

    private void applyReachBrowseAdapterSelection(int listPosition) {
        if (listReachBrowse == null) return;
        if (listPosition >= reachBrowseHeaderOffset()) {
            reachBrowseHeaderFocusIdx = -1;
        }
        int adapterIndex = reachBrowseAdapterIndex(listPosition);
        android.widget.ListAdapter ad = listReachBrowse.getAdapter();
        if (ad instanceof ReachChatRoomsAdapter) {
            ((ReachChatRoomsAdapter) ad).setSelectedPosition(adapterIndex);
        } else if (ad instanceof ReachInboxAdapter) {
            ((ReachInboxAdapter) ad).setSelectedPosition(adapterIndex);
        } else if (ad instanceof ReachUsersAdapter) {
            ((ReachUsersAdapter) ad).setSelectedPosition(adapterIndex);
        } else if (ad instanceof ReachInterestsAdapter) {
            ((ReachInterestsAdapter) ad).setSelectedPosition(adapterIndex);
        }
    }

    private void onReachBrowseListItemSelected(int listPosition) {
        if (listReachBrowse == null) return;
        int adapterIndex = reachBrowseAdapterIndex(listPosition);
        if (adapterIndex < 0) return;
        android.widget.ListAdapter ad = listReachBrowse.getAdapter();
        if (ad instanceof ReachInterestsAdapter) {
            ReachInterestsAdapter ia = (ReachInterestsAdapter) ad;
            if (!ia.isSelectable(adapterIndex)) return;
        }
        applyReachBrowseAdapterSelection(listPosition);
        if (ad instanceof ReachChatRoomsAdapter) {
            ReachChatRoomsAdapter ca = (ReachChatRoomsAdapter) ad;
            if (ca.isShowMorePosition(adapterIndex)) {
                ca.showMore();
                return;
            }
        }
        if (ad instanceof ReachInboxAdapter) {
            String peer = ((ReachInboxAdapter) ad).peerAt(adapterIndex);
            if (peer != null) watchSoulseekPeer(peer);
        } else if (ad instanceof ReachUsersAdapter) {
            ReachDirectoryUser u = ((ReachUsersAdapter) ad).userAt(adapterIndex);
            if (u != null) watchSoulseekPeer(u.username);
        }
    }

    private boolean isReachBrowseListActive() {
        return currentScreenState == STATE_SETTINGS
                && reachBrowseHost != null
                && reachBrowseHost.getVisibility() == View.VISIBLE
                && listReachBrowse != null
                && listReachBrowse.getAdapter() != null;
    }

    private boolean isReachBrowseFocusValid() {
        if (!isReachBrowseListActive()) return false;
        View f = getCurrentFocus();
        if (f != null && f.isShown() && f.isFocusable()) {
            if (indexOfReachBrowseHeader(f) >= 0) return true;
            if (listReachBrowse != null && isViewDescendantOf(f, listReachBrowse)) return true;
        }
        if (reachBrowseHeaderFocusIdx >= 0 && reachBrowseHeaderFocusIdx < reachBrowseHeaderViews.size()) {
            View h = reachBrowseHeaderViews.get(reachBrowseHeaderFocusIdx);
            if (h != null && h.isShown() && (h.hasFocus() || h.isFocused())) return true;
        }
        return false;
    }

    /** Re-seed wheel focus when Reach browse list lost highlight (API 17 ListView quirk). */
    private boolean ensureReachBrowseListFocus() {
        if (!isReachBrowseListActive()) return false;
        if (isReachBrowseFocusValid()) return false;
        focusFirstReachBrowseDataRow();
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("screen", settingsSubScreenKey);
            DebugSessionLog.log("MainActivity.ensureReachBrowseListFocus", "reseed", "H-FOCUS1", d);
        } catch (Exception ignored) {}
        // #endregion
        return true;
    }

    /**
     * Reach Messages / chat rooms / conversation thread wheel nav.
     * ponytail: DPAD_UP/DOWN (19/20) are swallowed by ListView before Activity.onKeyDown on API 17 —
     * call from dispatchKeyEvent before super so index-driven highlight always runs.
     */
    private boolean handleReachSettingsWheelKeyDown(int keyCode, KeyEvent event) {
        if (currentScreenState != STATE_SETTINGS || event.getAction() != KeyEvent.ACTION_DOWN) {
            return false;
        }
        if (!Y1InputKeys.isWheelKey(keyCode)) return false;
        if (isThemeListActive()) return false;
        if (isConversationThreadActive()) {
            int delta = Y1InputKeys.isWheelUp(keyCode) ? -1 : 1;
            if (moveConversationListFocus(delta) || ensureConversationListFocus()) {
                clickFeedback();
            }
            return true;
        }
        if (!isReachBrowseListActive()) return false;
        int delta = Y1InputKeys.isWheelUp(keyCode) ? -1 : 1;
        boolean moved = moveReachBrowseListFocus(delta) || ensureReachBrowseListFocus();
        if (moved) clickFeedback();
        // #region agent log
        if (event.getRepeatCount() == 0) {
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("keyCode", keyCode);
                d.put("delta", delta);
                d.put("moved", moved);
                d.put("screen", settingsSubScreenKey);
                DebugSessionLog.log("MainActivity.handleReachSettingsWheelKeyDown",
                        "reach wheel handled", "H-DISPATCH", d);
            } catch (Exception ignored) {}
        }
        // #endregion
        return true;
    }

    private void focusReachBrowseListPosition(int listPosition) {
        reachBrowseHeaderFocusIdx = -1;
        applyReachBrowseAdapterSelection(listPosition);
        FocusScrollHelper.focusListPosition(listReachBrowse, listPosition);
    }

    private boolean moveReachBrowseListFocus(int delta) {
        if (!isReachBrowseListActive() || delta == 0) return false;
        int headerIdx = reachBrowseActiveHeaderIndex();
        if (headerIdx >= 0) {
            int nextHeader = headerIdx + (delta < 0 ? -1 : 1);
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("headerIdx", headerIdx);
                d.put("nextHeader", nextHeader);
                d.put("delta", delta);
                DebugSessionLog.log("MainActivity.moveReachBrowseListFocus",
                        "header step", "H-HEADER", d);
            } catch (Exception ignored) {}
            // #endregion
            if (nextHeader >= 0 && nextHeader < reachBrowseHeaderViews.size()) {
                return focusReachBrowseHeaderIndex(nextHeader);
            }
            if (delta > 0) {
                android.widget.ListAdapter ad = listReachBrowse.getAdapter();
                int adapterRows = ad != null ? ad.getCount() : 0;
                if (adapterRows > 0) {
                    int headerCount = reachBrowseHeaderOffset();
                    int next = headerCount;
                    if (ad instanceof ReachInterestsAdapter) {
                        ReachInterestsAdapter ia = (ReachInterestsAdapter) ad;
                        int maxPos = headerCount + adapterRows - 1;
                        while (next <= maxPos && !ia.isSelectable(next - headerCount)) next++;
                    } else if (ad instanceof ReachUsersAdapter) {
                        ReachUsersAdapter ua = (ReachUsersAdapter) ad;
                        int maxPos = headerCount + adapterRows - 1;
                        while (next <= maxPos && !ua.isWheelSelectable(next - headerCount)) next++;
                    } else if (ad instanceof ReachChatRoomsAdapter) {
                        ReachChatRoomsAdapter ca = (ReachChatRoomsAdapter) ad;
                        int maxPos = headerCount + adapterRows - 1;
                        while (next <= maxPos && !ca.isWheelSelectable(next - headerCount)) next++;
                    } else {
                        int maxPos = headerCount + adapterRows - 1;
                        while (next <= maxPos && !ad.isEnabled(next - headerCount)) next++;
                    }
                    if (next <= headerCount + adapterRows - 1) {
                        focusReachBrowseListPosition(next);
                        return true;
                    }
                }
            }
            return false;
        }
        android.widget.ListAdapter ad = listReachBrowse.getAdapter();
        if (ad == null) return false;
        int adapterRows = ad.getCount();
        int headerCount = reachBrowseHeaderOffset();
        if (adapterRows <= 0) {
            if (!reachBrowseHeaderViews.isEmpty()) {
                int idx = delta < 0 ? reachBrowseHeaderViews.size() - 1 : 0;
                return focusReachBrowseHeaderIndex(idx);
            }
            return false;
        }
        int pos = reachBrowseFocusedListPosition(ad);
        int next = pos + (delta < 0 ? -1 : 1);
        int maxPos = headerCount + adapterRows - 1;
        if (delta < 0 && next < headerCount) {
            return focusReachBrowseHeaderIndex(reachBrowseHeaderViews.size() - 1);
        }
        if (ad instanceof ReachInterestsAdapter) {
            ReachInterestsAdapter ia = (ReachInterestsAdapter) ad;
            while (next >= headerCount && next <= maxPos) {
                int adapterIndex = next - headerCount;
                if (ia.isSelectable(adapterIndex)) break;
                next += (delta < 0 ? -1 : 1);
            }
        } else if (ad instanceof ReachUsersAdapter) {
            ReachUsersAdapter ua = (ReachUsersAdapter) ad;
            if (delta > 0) {
                int adapterIndex = pos - headerCount;
                if (adapterIndex == ua.getDataCount() - 1 && ua.hasShowMoreRow()) {
                    ua.showMore();
                    return true;
                }
            }
            while (next >= headerCount && next <= maxPos) {
                int adapterIndex = next - headerCount;
                if (ua.isWheelSelectable(adapterIndex)) break;
                next += (delta < 0 ? -1 : 1);
            }
        } else if (ad instanceof ReachChatRoomsAdapter) {
            ReachChatRoomsAdapter ca = (ReachChatRoomsAdapter) ad;
            if (delta > 0) {
                int adapterIndex = pos - headerCount;
                if (adapterIndex == ca.getDataCount() - 1 && ca.hasShowMoreRow()) {
                    ca.showMore();
                    return true;
                }
            }
            while (next >= headerCount && next <= maxPos) {
                int adapterIndex = next - headerCount;
                if (ca.isWheelSelectable(adapterIndex)) break;
                next += (delta < 0 ? -1 : 1);
            }
        } else {
            while (next >= headerCount && next <= maxPos && !ad.isEnabled(next - headerCount)) {
                next += (delta < 0 ? -1 : 1);
            }
        }
        if (next < headerCount || next > maxPos) {
            // ponytail: disabled/status rows can decrement next below headerCount — step to header, not dead-end.
            if (delta < 0 && next < headerCount && !reachBrowseHeaderViews.isEmpty()) {
                return focusReachBrowseHeaderIndex(reachBrowseHeaderViews.size() - 1);
            }
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("delta", delta);
                d.put("pos", pos);
                d.put("next", next);
                d.put("screen", settingsSubScreenKey);
                DebugSessionLog.log("MainActivity.moveReachBrowseListFocus", "at limit", "H-FOCUS3", d);
            } catch (Exception ignored) {}
            // #endregion
            return false;
        }
        focusReachBrowseListPosition(next);
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("delta", delta);
            d.put("next", next);
            d.put("adapterRows", adapterRows);
            d.put("screen", settingsSubScreenKey);
            DebugAgentLog.log(this, "MainActivity.moveReachBrowseListFocus",
                    "adapter row focus", "H-CHAT", d);
        } catch (Exception ignored) {}
        // #endregion
        return true;
    }

    private void debouncedRoomListUpdate(final java.util.List<SoulseekWire.RoomEntry> rooms) {
        pendingRoomListSnapshot = rooms;
        soulseekUiHandler.removeCallbacks(roomListDebounceRunnable);
        soulseekUiHandler.postDelayed(roomListDebounceRunnable, 300);
    }

    private int conversationRowHeightPx() {
        return ReachMessageRow.measureListRowHeight(this);
    }

    private void applyStatusBarTheme() {
        View statusBar = findViewById(R.id.layout_status_bar);
        if (statusBar != null) {
            statusBar.setBackgroundColor(ThemeManager.getStatusBarBackgroundColor());
        }
        int statusTextColor = ThemeManager.getStatusBarTextColor();
        if (tvStatusClock != null) {
            ThemeManager.applyThemedTextStyle(tvStatusClock, statusTextColor);
            applyStatusBarTitleMarquee();
        }
        if (tvStatusBattery != null) ThemeManager.applyThemedTextStyle(tvStatusBattery, statusTextColor);
        refreshWifiStatusIcon();
    }

    /** Status bar Wi-Fi tint: theme status text when match-font is on, else white. */
    private int statusBarWifiTintColor() {
        if (!statusBarMatchFont) return 0xFFFFFFFF;
        return ThemeManager.getStatusBarTextColor();
    }

    private void refreshWifiStatusIcon() {
        if (ivStatusWifi == null) return;
        try {
            WifiManager wm = (WifiManager) getApplicationContext().getSystemService(Context.WIFI_SERVICE);
            if (wm == null || !wm.isWifiEnabled()) {
                ivStatusWifi.setVisibility(View.GONE);
                return;
            }
            ivStatusWifi.setVisibility(View.VISIBLE);
            WifiInfo info = wm.getConnectionInfo();
            boolean connected = info != null && info.getNetworkId() != -1;
            int signalIdx = 0;
            if (connected && info != null) {
                signalIdx = ThemeManager.wifiSignalIndex(info.getRssi());
            }
            Bitmap themed = ThemeManager.getWifiIcon(signalIdx);
            if (themed != null) {
                ivStatusWifi.setImageBitmap(themed);
            } else {
                int res = R.drawable.ic_wifi_signal_1;
                if (signalIdx >= 2) res = R.drawable.ic_wifi_signal_3;
                else if (signalIdx == 1) res = R.drawable.ic_wifi_signal_2;
                ivStatusWifi.setImageResource(res);
            }
            ivStatusWifi.setColorFilter(statusBarWifiTintColor(), android.graphics.PorterDuff.Mode.SRC_IN);
        } catch (Exception e) {
            ivStatusWifi.setVisibility(View.GONE);
        }
    }

    private View getHomeMenuRow(int index) {
        if (containerHomeMenuItems == null || index < 0
                || index >= containerHomeMenuItems.getChildCount()) return null;
        return containerHomeMenuItems.getChildAt(index);
    }

    private void requestFirstHomeMenuFocus() {
        scrollHomeMenuToIndex(focusedHomeMenuIndex);
    }

    /** Index-driven home menu move — wheel keys must not rely on View focus on API 17. */
    private boolean moveHomeMenuFocus(int delta) {
        if (ActiveThemeEngine.isJjMode() && jjHomeOverlay != null) {
            int total = jjHomeOverlay.getChildCount();
            if (total == 0 || delta == 0) return false;
            int next = focusedHomeMenuIndex + delta;
            if (next < 0 || next >= total) return false;
            focusedHomeMenuIndex = next;
            View child = jjHomeOverlay.getChildAt(next);
            if (child != null) child.requestFocus();
            return true;
        }
        if (containerHomeMenuItems == null || delta == 0) return false;
        int total = containerHomeMenuItems.getChildCount();
        if (total == 0) return false;
        int next = focusedHomeMenuIndex + delta;
        if (next < 0 || next >= total) {
            if (menuScroll != null) Y1ScrollIndicators.edgeGlowAtLimit(menuScroll, delta);
            return false;
        }
        focusedHomeMenuIndex = next;
        scrollHomeMenuToIndex(next);
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("next", next);
            d.put("total", total);
            d.put("scrollY", menuScroll != null ? menuScroll.getScrollY() : -1);
            View row = getHomeMenuRow(next);
            if (row != null) {
                TextView tv = (TextView) row.getTag(HOME_MENU_TAG_LABEL);
                d.put("label", tv != null && tv.getText() != null ? tv.getText().toString() : "");
            }
            if (next >= 0 && next < homeMenuEntries.size()) {
                d.put("entryId", homeMenuEntries.get(next).id);
            } else if (next == total - 1 && HomeMenuConfig.shouldShowMoreTile(prefs,
                    ConnectivityHelper.isOnline(this), ConnectivityHelper.hasLocalNetwork(this))) {
                d.put("entryId", HomeMenuConfig.ID_MORE);
            }
            DebugAgentLog.log(this, "MainActivity.moveHomeMenuFocus", "focus moved", "H-D", d);
        } catch (Exception ignored) {}
        // #endregion
        return true;
    }

    private void refreshHomeMenuRowStyles() {
        if (containerHomeMenuItems == null) return;
        for (int i = 0; i < containerHomeMenuItems.getChildCount(); i++) {
            View row = containerHomeMenuItems.getChildAt(i);
            if (!(row instanceof FrameLayout)) continue;
            TextView label = (TextView) row.getTag(HOME_MENU_TAG_LABEL);
            ImageView arrow = (ImageView) row.getTag(HOME_MENU_TAG_ARROW);
            boolean focused = i == focusedHomeMenuIndex;
            applyY1ListRowStyle(row, focused, label, null, arrow, Y1_ROW_HOME);
        }
    }

    private boolean isNowPlayingHomeFocused() {
        return focusedHomeMenuIndex >= 0 && focusedHomeMenuIndex < homeMenuEntries.size()
                && HomeMenuConfig.ID_NOW_PLAYING.equals(homeMenuEntries.get(focusedHomeMenuIndex).id);
    }

    private Bitmap resolveHomeMenuPreviewIconForId(String id) {
        HomeMenuConfig.Entry e = HomeMenuConfig.find(id);
        if (e == null) return null;
        return ThemeManager.getHomeMenuIcon(this, e);
    }

    private void applyAllHomeMenuRowStyles() {
        refreshHomeMenuRowStyles();
    }

    private void applyAllSettingsRowStyles() {
        if (containerSettingsItems == null) return;
        View focused = getCurrentFocus();
        for (int i = 0; i < containerSettingsItems.getChildCount(); i++) {
            View row = containerSettingsItems.getChildAt(i);
            if (!(row instanceof LinearLayout)) continue;
            boolean hasFocus = row == focused;
            TextView tvLeft = null;
            TextView tvRight = null;
            ImageView arrow = null;
            LinearLayout layout = (LinearLayout) row;
            for (int j = 0; j < layout.getChildCount(); j++) {
                View child = layout.getChildAt(j);
                if (child instanceof TextView) {
                    if ("inline_state".equals(child.getTag())) tvRight = (TextView) child;
                    else if (tvLeft == null) tvLeft = (TextView) child;
                } else if (child instanceof ImageView) {
                    arrow = (ImageView) child;
                }
            }
            if (tvLeft != null) {
                int rowW = row.getWidth() > 0 ? row.getWidth() : y1ActiveRowWidthPx();
                row.setBackground(getY1RowBackground(hasFocus, rowW, Y1_ROW_MENU));
                applyY1ListRowStyle(row, hasFocus, tvLeft, tvRight, arrow, Y1_ROW_MENU);
            }
        }
    }

    private void applyY1ListRowStyle(View row, boolean focused, TextView label, TextView value,
                                     ImageView arrow, int rowKind) {
        int w = row.getWidth() > 0 ? row.getWidth() : y1ActiveRowWidthPx();
        row.setBackground(getY1RowBackground(focused, w, rowKind));
        if (label != null) {
            label.setTypeface(ThemeManager.getCustomFont(), android.graphics.Typeface.BOLD);
            ThemeManager.applyThemedTextStyle(label, focused
                    ? y1RowTextColorSelected(rowKind) : y1RowTextColorNormal(rowKind));
            label.setSelected(focused);
            if (focused) enableMarquee(label);
            else {
                label.setEllipsize(TextUtils.TruncateAt.END);
                label.setHorizontallyScrolling(false);
            }
        }
        if (value != null) {
            String t = value.getText().toString();
            if (t.equals("ON") || t.equals("ONE") || t.equals("ALL") || t.equals("OFF"))
                ThemeManager.applyThemedTextStyle(value, focused
                        ? y1RowTextColorSelected(rowKind) : y1RowTextColorNormal(rowKind));
            else if (!t.isEmpty())
                ThemeManager.applyThemedTextStyle(value, focused
                        ? y1RowTextColorSelected(rowKind) : y1RowTextColorNormal(rowKind));
            enableMarquee(value);
        }
        if (arrow != null) arrow.setVisibility(focused ? View.VISIBLE : View.GONE);
    }

    private void applyY1ListRowStyle(View row, boolean focused, TextView label, TextView value, ImageView arrow) {
        applyY1ListRowStyle(row, focused, label, value, arrow, y1RowKindForScreen());
    }

    /** Menu rows survive under NP/Flow — defer connectivity scan + removeAllViews until slide ends. */
    private boolean shouldDeferHomeMenuRebuild(int leavingScreen, boolean deferOutgoingHide) {
        if (!deferOutgoingHide || containerHomeMenuItems == null) return false;
        if (containerHomeMenuItems.getChildCount() <= 0) return false;
        return leavingScreen == STATE_PLAYER || leavingScreen == STATE_FLOW;
    }

    private void buildHomeMenu() {
        if (containerHomeMenuItems == null) return;
        if (android.os.Looper.myLooper() != android.os.Looper.getMainLooper()) {
            runOnUiThread(new Runnable() {
                @Override public void run() { buildHomeMenu(); }
            });
            return;
        }
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("buildGen", homeMenuBuildGen + 1);
            d.put("prevChildCount", containerHomeMenuItems.getChildCount());
            d.put("thread", Thread.currentThread().getName());
            DebugAgentLog.log(this, "MainActivity.buildHomeMenu", "build start", "H-E", d);
        } catch (Exception ignored) {}
        // #endregion
        if (ActiveThemeEngine.isJjMode()) {
            buildJjHomeMenu();
            return;
        }
        if (menuScroll != null) menuScroll.setVisibility(View.VISIBLE);
        if (jjHomeOverlay != null && menuListHost != null) {
            menuListHost.removeView(jjHomeOverlay);
            jjHomeOverlay = null;
        }
        final int buildGen = ++homeMenuBuildGen;
        final boolean online = ConnectivityHelper.isOnline(this);
        final boolean onLan = ConnectivityHelper.hasLocalNetwork(this);
        homeMenuEntries = HomeMenuConfig.loadVisibleForDisplay(prefs, online, onLan);
        final boolean showNowPlaying = shouldShowNowPlayingHome();
        if (showNowPlaying) {
            boolean hasNowPlaying = false;
            for (HomeMenuConfig.Entry e : homeMenuEntries) {
                if (HomeMenuConfig.ID_NOW_PLAYING.equals(e.id)) {
                    hasNowPlaying = true;
                    break;
                }
            }
            if (!hasNowPlaying) {
                HomeMenuConfig.Entry np = HomeMenuConfig.find(HomeMenuConfig.ID_NOW_PLAYING);
                if (np != null) homeMenuEntries.add(0, np);
            }
        }
        java.util.Iterator<HomeMenuConfig.Entry> homeIt = homeMenuEntries.iterator();
        while (homeIt.hasNext()) {
            if (HomeMenuConfig.ID_NOW_PLAYING.equals(homeIt.next().id) && !showNowPlaying) {
                homeIt.remove();
            }
        }
        final boolean showMore = HomeMenuConfig.shouldShowMoreTile(prefs, online, onLan);
        int totalRows = homeMenuEntries.size() + (showMore ? 1 : 0);
        if (focusedHomeMenuIndex >= totalRows) {
            focusedHomeMenuIndex = Math.max(0, totalRows - 1);
            if (menuScroll != null) menuScroll.scrollTo(0, 0);
        }
        // ponytail: build off-container first — stale-gen abort must not leave removeAllViews() with 0 rows.
        final java.util.ArrayList<View> pendingRows = new java.util.ArrayList<View>(totalRows);
        for (int i = 0; i < homeMenuEntries.size(); i++) {
            if (buildGen != homeMenuBuildGen) {
                // #region agent log
                try {
                    org.json.JSONObject d = new org.json.JSONObject();
                    d.put("staleGen", buildGen);
                    d.put("currentGen", homeMenuBuildGen);
                    d.put("abortedAtRow", i);
                    d.put("childCount", containerHomeMenuItems.getChildCount());
                    DebugAgentLog.log(this, "MainActivity.buildHomeMenu",
                            "stale build aborted", "H-HOME-B", d);
                } catch (Exception ignored) {}
                // #endregion
                return;
            }
            pendingRows.add(createHomeMenuRow(homeMenuEntries.get(i), i));
        }
        if (showMore) {
            if (buildGen != homeMenuBuildGen) return;
            pendingRows.add(createHomeMoreTileRow(homeMenuEntries.size()));
        }
        if (buildGen != homeMenuBuildGen) return;
        containerHomeMenuItems.removeAllViews();
        if (menuScroll != null) menuScroll.scrollTo(0, 0);
        for (View row : pendingRows) {
            containerHomeMenuItems.addView(row, homeMenuRowLayoutParams());
        }
        int panelH = menuListHeightPx > 0 ? menuListHeightPx
                : (int) getResources().getDimension(R.dimen.y1_menu_height);
        applyMenuPanelBackground(menuListHost, y1RowWidthPx, panelH,
                (int) getResources().getDimension(R.dimen.y1_menu_height));
        if (buildGen != homeMenuBuildGen) return;
        int childCount = containerHomeMenuItems.getChildCount();
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("buildGen", buildGen);
            d.put("expectedRows", totalRows);
            d.put("childCount", childCount);
            d.put("entryCount", homeMenuEntries.size());
            d.put("showMore", showMore);
            d.put("showNowPlaying", showNowPlaying);
            d.put("menuListHeightPx", menuListHeightPx);
            d.put("focusedIndex", focusedHomeMenuIndex);
            java.util.Set<String> idSet = new java.util.HashSet<String>();
            boolean dupEntryIds = false;
            org.json.JSONArray entryIds = new org.json.JSONArray();
            for (HomeMenuConfig.Entry e : homeMenuEntries) {
                entryIds.put(e.id);
                if (!idSet.add(e.id)) dupEntryIds = true;
            }
            d.put("entryIds", entryIds);
            d.put("dupEntryIds", dupEntryIds);
            org.json.JSONArray rowLabels = new org.json.JSONArray();
            java.util.Set<String> labelSet = new java.util.HashSet<String>();
            boolean dupLabels = false;
            boolean musicTwice = false;
            int musicCount = 0;
            for (int i = 0; i < childCount; i++) {
                View row = containerHomeMenuItems.getChildAt(i);
                String lbl = "";
                if (row != null) {
                    TextView tv = (TextView) row.getTag(HOME_MENU_TAG_LABEL);
                    if (tv != null && tv.getText() != null) lbl = tv.getText().toString();
                }
                rowLabels.put(i + ":" + lbl);
                if (!lbl.isEmpty() && !labelSet.add(lbl)) dupLabels = true;
                if (getString(R.string.home_menu_music).equals(lbl)) musicCount++;
            }
            d.put("rowLabels", rowLabels);
            d.put("dupLabels", dupLabels);
            d.put("musicLabelCount", musicCount);
            d.put("musicTwice", musicCount >= 2);
            if (menuScroll != null && containerHomeMenuItems != null) {
                d.put("scrollY", menuScroll.getScrollY());
                d.put("scrollHeight", menuScroll.getHeight());
                d.put("contentHeight", containerHomeMenuItems.getHeight());
            }
            d.put("countMismatch", childCount != totalRows);
            d.put("panelSolid", false);
            d.put("thread", Thread.currentThread().getName());
            DebugAgentLog.log(this, "MainActivity.buildHomeMenu", "home menu built", "H-HOME", d);
            // #region agent log
            try {
                org.json.JSONObject ds = new org.json.JSONObject();
                ds.put("childCount", childCount);
                ds.put("totalRows", totalRows);
                ds.put("entryCount", homeMenuEntries.size());
                ds.put("focusedIndex", focusedHomeMenuIndex);
                ds.put("buildGen", buildGen);
                DebugSessionLog.log("MainActivity.buildHomeMenu", "home built", "H-HOME", ds);
            } catch (Exception ignored) {}
            // #endregion
        } catch (Exception ignored) {}
        // #endregion
        if (childCount != totalRows) {
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("expected", totalRows);
                d.put("actual", childCount);
                DebugAgentLog.log(this, "MainActivity.buildHomeMenu", "row count mismatch", "H-B", d);
            } catch (Exception ignored) {}
        }
        if (childCount == 0 && totalRows > 0) {
            scheduleRebuildHomeMenuIfVisible();
        }
        scrollHomeMenuToIndex(focusedHomeMenuIndex);
        refreshHomeMenuRowStyles();
        if (containerHomeMenuItems != null) containerHomeMenuItems.requestLayout();
        nowPlayingHomeMenuVisible = shouldShowNowPlayingHome();
    }

    /** JJ experimental home: absolute {@code main_menu[]} layout from active JJ theme. */
    private void buildJjHomeMenu() {
        if (android.os.Looper.myLooper() != android.os.Looper.getMainLooper()) {
            runOnUiThread(new Runnable() {
                @Override public void run() { buildJjHomeMenu(); }
            });
            return;
        }
        final int buildGen = ++homeMenuBuildGen;
        containerHomeMenuItems.removeAllViews();
        if (menuScroll != null) menuScroll.setVisibility(View.GONE);
        if (jjHomeOverlay != null && menuListHost != null) {
            menuListHost.removeView(jjHomeOverlay);
            jjHomeOverlay = null;
        }
        if (menuListHost == null) return;

        float density = getResources().getDisplayMetrics().density;
        jjHomeOverlay = new FrameLayout(this);
        jjHomeOverlay.setFocusable(false);
        menuListHost.addView(jjHomeOverlay, new FrameLayout.LayoutParams(
                FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.MATCH_PARENT));

        JjThemeManager.ThemeData theme = JjThemeManager.getCurrentTheme();
        int panelH = menuListHeightPx > 0 ? menuListHeightPx
                : (int) getResources().getDimension(R.dimen.y1_menu_height);
        applyMenuPanelBackground(menuListHost, y1RowWidthPx, panelH,
                (int) getResources().getDimension(R.dimen.y1_menu_height));

        final List<JjThemeManager.MenuElement> elements = theme.menuElements;
        int focusIdx = 0;
        for (int i = 0; i < elements.size(); i++) {
            if (buildGen != homeMenuBuildGen) return;
            final JjThemeManager.MenuElement el = elements.get(i);
            if (!"button".equals(el.type)) continue;
            final int rowIdx = i;
            Button btn = createListButton(el.textNormal != null && !el.textNormal.isEmpty()
                    ? el.textNormal : " ");
            int w = el.width > 0 ? (int) (el.width * density) : y1ActiveRowWidthPx();
            int h = el.height > 0 ? (int) (el.height * density) : y1RowHeightPx;
            FrameLayout.LayoutParams lp = new FrameLayout.LayoutParams(w, h);
            lp.leftMargin = (int) (el.x * density);
            lp.topMargin = (int) (el.y * density);
            final String homeId = mapJjActionToHomeId(el.action);
            btn.setOnClickListener(new View.OnClickListener() {
                @Override
                public void onClick(View v) {
                    clickFeedback();
                    if (homeId != null) onHomeMenuActivate(homeId);
                }
            });
            btn.setOnFocusChangeListener(new View.OnFocusChangeListener() {
                @Override
                public void onFocusChange(View v, boolean hasFocus) {
                    if (hasFocus) {
                        focusedHomeMenuIndex = rowIdx;
                        updateStatusBarTitle();
                    }
                }
            });
            jjHomeOverlay.addView(btn, lp);
            if (el.focusIndex > 0 && focusIdx == 0) {
                focusIdx = rowIdx;
            }
        }
        if (buildGen != homeMenuBuildGen) return;
        if (jjHomeOverlay.getChildCount() > 0) {
            int child = Math.min(focusedHomeMenuIndex, jjHomeOverlay.getChildCount() - 1);
            if (child < 0) child = 0;
            jjHomeOverlay.getChildAt(child).requestFocus();
        }
    }

    private String mapJjActionToHomeId(String action) {
        if (action == null) return null;
        if ("OPEN_PLAYER".equals(action)) return HomeMenuConfig.ID_NOW_PLAYING;
        if ("OPEN_BROWSER".equals(action)) return HomeMenuConfig.ID_MUSIC;
        if ("OPEN_BLUETOOTH".equals(action)) return HomeMenuConfig.ID_BLUETOOTH;
        if ("OPEN_SETTINGS".equals(action)) return HomeMenuConfig.ID_SETTINGS;
        if ("OPEN_WEBSERVER".equals(action)) return HomeMenuConfig.ID_PC_UPLOAD;
        return null;
    }

    private void applyJjThemeSelection(int index) {
        ActiveThemeEngine.applyJjThemeIndex(this, index);
        JjThemeManager.ThemeData theme = JjThemeManager.availableThemes.get(index);
        Toast.makeText(this, getString(R.string.toast_theme_applied, theme.name), Toast.LENGTH_SHORT).show();
        applyThemeToMainMenu();
        scheduleRebuildHomeMenuIfVisible();
        rebuildThemeBrowserRows();
        refreshThemeBrowserList();
    }

    private LinearLayout.LayoutParams homeMenuRowLayoutParams() {
        LinearLayout.LayoutParams lp = new LinearLayout.LayoutParams(
                isFullWidthMenus ? LinearLayout.LayoutParams.MATCH_PARENT : y1ActiveRowWidthPx(),
                y1RowHeightPx);
        lp.setMargins(0, 1, 0, 1);
        return lp;
    }

    private FrameLayout createHomeMenuRow(final HomeMenuConfig.Entry entry, final int idx) {
        FrameLayout row = createHomeMenuRowShell(y1HomeArrowExtraInsetPx());
        TextView label = (TextView) row.getTag(HOME_MENU_TAG_LABEL);
        ImageView arrow = (ImageView) row.getTag(HOME_MENU_TAG_ARROW);
        label.setText(getString(entry.labelResId));
        row.setOnFocusChangeListener(new View.OnFocusChangeListener() {
            @Override
            public void onFocusChange(View v, boolean hasFocus) {
                if (hasFocus) {
                    focusedHomeMenuIndex = idx;
                    updateStatusBarTitle();
                    updateHomeMenuPreview(idx);
                }
                refreshHomeMenuRowStyles();
            }
        });
        row.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                clickFeedback();
                onHomeMenuActivate(entry.id);
            }
        });
        applyY1ListRowStyle(row, idx == focusedHomeMenuIndex, label, null, arrow, Y1_ROW_HOME);
        return row;
    }

    private FrameLayout createHomeMoreTileRow(final int idx) {
        FrameLayout row = createHomeMenuRowShell(y1HomeArrowExtraInsetPx());
        TextView label = (TextView) row.getTag(HOME_MENU_TAG_LABEL);
        ImageView arrow = (ImageView) row.getTag(HOME_MENU_TAG_ARROW);
        label.setText(getString(R.string.home_menu_more));
        arrow.setVisibility(View.VISIBLE);
        row.setOnFocusChangeListener(new View.OnFocusChangeListener() {
            @Override
            public void onFocusChange(View v, boolean hasFocus) {
                if (hasFocus) {
                    focusedHomeMenuIndex = idx;
                    updateStatusBarTitle();
                    ivMenuPreview.setVisibility(View.GONE);
                    if (tvMenuPreviewTitle != null) tvMenuPreviewTitle.setVisibility(View.GONE);
                    if (tvMenuPreviewArtist != null) tvMenuPreviewArtist.setVisibility(View.GONE);
                }
                refreshHomeMenuRowStyles();
            }
        });
        row.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                clickFeedback();
                onHomeMenuActivate(HomeMenuConfig.ID_MORE);
            }
        });
        applyY1ListRowStyle(row, idx == focusedHomeMenuIndex, label, null, arrow, Y1_ROW_HOME);
        return row;
    }

    /** Home list host has no outer padding — nudge selection arrows left so they are not clipped. */
    private int y1HomeArrowExtraInsetPx() {
        return (int) getResources().getDimension(R.dimen.y1_home_arrow_extra_inset);
    }

    /** ponytail: ListView recycles rows — tag label/arrow on shell for getView */
    private FrameLayout createHomeMenuRowShell() {
        return createHomeMenuRowShell(0);
    }

    private FrameLayout createHomeMenuRowShell(int extraArrowInsetEndPx) {
        int textPadLeft = (int) getResources().getDimension(R.dimen.y1_menu_text_pad_left);
        float menuTextPx = getResources().getDimension(R.dimen.y1_menu_text_size);
        Bitmap arrowBmp = ThemeManager.getScaledItemRightArrow(y1RowHeightPx);
        int[] arrowLayout = y1ArrowLayout(arrowBmp, extraArrowInsetEndPx);
        int arrowMarginEnd = (int) getResources().getDimension(R.dimen.y1_arrow_margin_end)
                + extraArrowInsetEndPx;

        FrameLayout row = new FrameLayout(this);
        row.setFocusable(true);
        row.setFocusableInTouchMode(true);
        row.setSoundEffectsEnabled(false);

        TextView label = new TextView(this);
        label.setFocusable(false);
        label.setTypeface(ThemeManager.getCustomFont(), android.graphics.Typeface.BOLD);
        label.setTextSize(android.util.TypedValue.COMPLEX_UNIT_PX, menuTextPx);
        label.setSingleLine(true);
        label.setEllipsize(TextUtils.TruncateAt.END);
        label.setGravity(android.view.Gravity.CENTER_VERTICAL | android.view.Gravity.START);
        label.setIncludeFontPadding(false);
        label.setBackgroundColor(0x00000000);
        ThemeManager.applyThemedTextStyle(label, ThemeManager.getHomeMenuTextColorNormal());
        FrameLayout.LayoutParams labelLp = new FrameLayout.LayoutParams(
                FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.MATCH_PARENT);
        labelLp.gravity = android.view.Gravity.CENTER_VERTICAL;
        labelLp.leftMargin = textPadLeft;
        labelLp.rightMargin = arrowLayout[2];
        row.addView(label, labelLp);

        ImageView arrow = new ImageView(this);
        arrow.setFocusable(false);
        arrow.setScaleType(ImageView.ScaleType.FIT_CENTER);
        if (arrowBmp != null) arrow.setImageBitmap(arrowBmp);
        arrow.setVisibility(View.GONE);
        FrameLayout.LayoutParams arrowLp = new FrameLayout.LayoutParams(arrowLayout[0], arrowLayout[1]);
        arrowLp.gravity = android.view.Gravity.CENTER_VERTICAL | android.view.Gravity.END;
        arrowLp.rightMargin = arrowMarginEnd;
        row.addView(arrow, arrowLp);

        row.setTag(HOME_MENU_TAG_LABEL, label);
        row.setTag(HOME_MENU_TAG_ARROW, arrow);
        return row;
    }

    private void scrollHomeMenuToIndex(int index) {
        if (containerHomeMenuItems == null || containerHomeMenuItems.getChildCount() == 0) return;
        if (index < 0 || index >= containerHomeMenuItems.getChildCount()) return;
        final int buildGen = homeMenuBuildGen;
        final View row = containerHomeMenuItems.getChildAt(index);
        if (row == null) return;
        row.post(new Runnable() {
            @Override
            public void run() {
                if (buildGen != homeMenuBuildGen) return;
                View target = getHomeMenuRow(index);
                if (target != null) {
                    target.requestFocus();
                    if (menuScroll != null) {
                        menuScroll.requestChildFocus(containerHomeMenuItems, target);
                        FocusScrollHelper.scrollToChildBottom(menuScroll, target);
                    }
                }
                refreshHomeMenuRowStyles();
                updateStatusBarTitle();
                updateHomeMenuPreview(focusedHomeMenuIndex);
            }
        });
    }

    private boolean shouldShowNowPlayingPreviewArt() {
        if (!playback.hasAnyQueue()) return false;
        if (currentScreenState == STATE_PLAYER) return true;
        try {
            return mediaPlayer != null && mediaPlayer.getDuration() > 0;
        } catch (Exception e) {
            return false;
        }
    }

    private void updateHomeMenuPreview(int index) {
        if (isFullWidthMenus || index < 0 || index >= homeMenuEntries.size()) return;

        String id = homeMenuEntries.get(index).id;
        if (HomeMenuConfig.ID_NOW_PLAYING.equals(id)) {
            if (shouldShowNowPlayingPreviewArt()) {
                if (lastAlbumArtBytes != null && lastAlbumArtBytes.length > 0) {
                    try {
                        BitmapFactory.Options opts = new BitmapFactory.Options();
                        opts.inSampleSize = 2;
                        ivMenuPreview.setImageBitmap(decorateAlbumArtForPreview(BitmapFactory.decodeByteArray(
                                lastAlbumArtBytes, 0, lastAlbumArtBytes.length, opts)));
                    } catch (Exception e) {
                        ivMenuPreview.setImageBitmap(decorateAlbumArtForPreview(ThemeManager.getCustomIcon(
                                "icon_default_album.png", this, R.drawable.default_album)));
                    }
                } else {
                    setMenuPreviewDefaultAlbumArt();
                }
                if (tvMenuPreviewTitle != null && tvMenuPreviewArtist != null && tvPlayerTitle != null) {
                    tvMenuPreviewTitle.setVisibility(View.VISIBLE);
                    tvMenuPreviewArtist.setVisibility(View.VISIBLE);
                    tvMenuPreviewTitle.setText(tvPlayerTitle.getText());
                    tvMenuPreviewArtist.setText(tvPlayerArtist != null ? tvPlayerArtist.getText() : "");
                }
            } else {
                Bitmap previewIcon = resolveHomeMenuPreviewIconForId(id);
                if (previewIcon != null) {
                    ivMenuPreview.setImageBitmap(previewIcon);
                    ivMenuPreview.setVisibility(View.VISIBLE);
                } else {
                    ivMenuPreview.setVisibility(View.GONE);
                }
                if (tvMenuPreviewTitle != null && tvMenuPreviewArtist != null) {
                    tvMenuPreviewTitle.setVisibility(View.GONE);
                    tvMenuPreviewArtist.setVisibility(View.GONE);
                }
            }
        } else {
            Bitmap previewIcon = resolveHomeMenuPreviewIconForId(id);
            if (previewIcon != null) {
                ivMenuPreview.setImageBitmap(previewIcon);
                ivMenuPreview.setVisibility(View.VISIBLE);
            } else {
                ivMenuPreview.setVisibility(View.GONE);
            }
            if (tvMenuPreviewTitle != null && tvMenuPreviewArtist != null) {
                tvMenuPreviewTitle.setVisibility(View.GONE);
                tvMenuPreviewArtist.setVisibility(View.GONE);
            }
        }
        MenuPreviewLayout.Spec previewSpec = MenuPreviewLayout.homeSpec(this, isHomeDesktopMaskActive());
        if (ivMenuPreview.getVisibility() == View.VISIBLE) {
            ivMenuPreview.setAlpha(1f);
            MenuPreviewLayout.applyImagePreview(ivMenuPreview, previewSpec);
        }
        if (previewSpec.hideTitlesBelowArt) {
            if (tvMenuPreviewTitle != null) tvMenuPreviewTitle.setVisibility(View.GONE);
            if (tvMenuPreviewArtist != null) tvMenuPreviewArtist.setVisibility(View.GONE);
        } else if (HomeMenuConfig.ID_NOW_PLAYING.equals(id) && shouldShowNowPlayingPreviewArt()
                && tvMenuPreviewTitle != null && tvMenuPreviewTitle.getVisibility() == View.VISIBLE) {
            int gap = (int) getResources().getDimension(R.dimen.y1_preview_title_gap);
            MenuPreviewLayout.layoutTitlesBelowArt(ivMenuPreview, tvMenuPreviewTitle, tvMenuPreviewArtist, gap);
            alignHomePreviewTitleWidth(tvMenuPreviewTitle, previewSpec);
            alignHomePreviewTitleWidth(tvMenuPreviewArtist, previewSpec);
        }
    }

    private void alignHomePreviewTitleWidth(TextView tv, MenuPreviewLayout.Spec spec) {
        if (tv == null || spec == null) return;
        ViewGroup.LayoutParams raw = tv.getLayoutParams();
        if (!(raw instanceof FrameLayout.LayoutParams)) return;
        FrameLayout.LayoutParams lp = (FrameLayout.LayoutParams) raw;
        lp.width = spec.paneWidthPx;
        lp.rightMargin = spec.marginEndPx;
        tv.setLayoutParams(lp);
    }

    private boolean shouldShowNowPlayingHome() {
        boolean show = playback.hasAnyQueue()
                || playback.isMusicActive() || playback.isPodcastActive();
        if (!show) {
            try {
                show = mediaPlayer != null && mediaPlayer.isPlaying();
            } catch (Exception ignored) {}
        }
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("show", show);
            d.put("queueSize", playback.unifiedQueue().size());
            d.put("musicActive", playback.isMusicActive());
            d.put("podcastActive", playback.isPodcastActive());
            d.put("screen", currentScreenState);
            d.put("npVisible", nowPlayingHomeMenuVisible);
            DebugAgentLog.log(this, "MainActivity.shouldShowNowPlayingHome", "gate", "H1-H3", d);
        } catch (Exception ignored) {}
        // #endregion
        return show;
    }

    private void syncNowPlayingHomeVisibility() {
        boolean show = shouldShowNowPlayingHome();
        if (show == nowPlayingHomeMenuVisible) return;
        nowPlayingHomeMenuVisible = show;
        if (!show) {
            lastAlbumArtBytes = null;
        }
        if (currentScreenState == STATE_MENU && containerHomeMenuItems != null) {
            scheduleRebuildHomeMenuIfVisible();
        }
        refreshContextQuickBarIfShowing();
    }

    private void refreshContextQuickBarIfShowing() {
        if (themedContextMenu == null || !themedContextMenu.isShowing()
                || themedContextMenu.isVolumeOnlyMode()) return;
        applyContextQuickBarChrome();
        themedContextMenu.replaceQuickBar(buildContextQuickBar());
    }

    /** Volume/brightness chips are array slots 7/6 — must be set before quick-bar chips are built. */
    private void applyContextQuickBarChrome() {
        if (themedContextMenu == null) return;
        themedContextMenu.setPrimaryEndQuickIndex(CONTEXT_QUICK_QUEUE_INDEX);
        themedContextMenu.setMediaSliderQuickIndices(CONTEXT_QUICK_VOLUME_INDEX,
                CONTEXT_QUICK_BRIGHTNESS_INDEX);
    }

    private void onHomeMenuActivate(String id) {
        if (HomeMenuConfig.ID_NOW_PLAYING.equals(id)) {
            if (playback.hasAnyQueue()) {
                changeScreen(STATE_PLAYER);
            } else {
                currentBrowserMode = BROWSER_ROOT;
                changeScreen(STATE_BROWSER);
            }
        } else if (HomeMenuConfig.ID_MUSIC.equals(id)) {
            currentBrowserMode = BROWSER_ROOT;
            changeScreen(STATE_BROWSER);
        } else if (HomeMenuConfig.ID_BLUETOOTH.equals(id)) {
            if (BluetoothExperiment.isEnabled(prefs)) {
                openScreenWithReturn(STATE_BLUETOOTH);
            } else {
                launchAndroidBluetoothSettings();
            }
        } else if (HomeMenuConfig.ID_SETTINGS.equals(id)) {
            changeScreen(STATE_SETTINGS);
        } else if (HomeMenuConfig.ID_RADIO.equals(id) || HomeMenuConfig.ID_FM.equals(id)) {
            if (com.solar.launcher.radio.RadioExperiment.isEnabled(prefs)) {
                changeScreen(MediaSuiteHost.STATE_RADIO);
            } else {
                launchMtkFmRadio();
            }
        } else if (HomeMenuConfig.ID_PC_UPLOAD.equals(id)) {
            if (!ConnectivityHelper.hasLocalNetwork(this)) {
                Toast.makeText(this, getString(R.string.toast_requires_wifi), Toast.LENGTH_SHORT).show();
                return;
            }
            openScreenWithReturn(STATE_WEBSERVER);
        } else if (HomeMenuConfig.ID_PODCASTS.equals(id)) {
            if (ConnectivityHelper.isOnline(this)) {
                changeScreen(STATE_PODCASTS);
            } else if (com.solar.launcher.podcast.PodcastLibrary.hasSavedContent()) {
                changeScreen(STATE_PODCASTS);
                buildPodcastSavedShowsUI();
            } else {
                Toast.makeText(this, getString(R.string.toast_internet_required), Toast.LENGTH_SHORT).show();
            }
        } else if (HomeMenuConfig.ID_SOULSEEK.equals(id)) {
            if (!requireInternet(R.string.toast_internet_required)) return;
            openGetMusicScreen();
        } else if (HomeMenuConfig.ID_THEMES.equals(id) || HomeMenuConfig.ID_GET_THEMES.equals(id)) {
            openThemesScreen(null);
        } else if (HomeMenuConfig.ID_MORE.equals(id)) {
            changeScreen(STATE_MORE);
        } else if (HomeMenuConfig.ID_VIDEOS.equals(id)) {
            changeScreen(MediaSuiteHost.STATE_VIDEOS);
        } else if (HomeMenuConfig.ID_PHOTOS.equals(id)) {
            changeScreen(MediaSuiteHost.STATE_PHOTOS);
        } else if (HomeMenuConfig.ID_AUDIOBOOKS.equals(id)) {
            Toast.makeText(this, getString(R.string.home_audiobooks_coming_soon), Toast.LENGTH_LONG).show();
        } else if (HomeMenuConfig.ID_APPS.equals(id)) {
            changeScreen(STATE_APPS);
        }
    }

    private void updateStatusBarTitle() {
        if (tvStatusClock == null) return;
        if (statusBarFlowHandoffCrossfade && FlowPlayerHandoff.isHandoffAnimating()) {
            return;
        }
        if (!statusBarShowsTitle && currentScreenState == STATE_MENU) {
            java.text.SimpleDateFormat sdf = new java.text.SimpleDateFormat("h:mm a", java.util.Locale.US);
            tvStatusClock.setText(sdf.format(new java.util.Date()));
        } else {
            tvStatusClock.setText(getStatusBarContextTitle());
        }
        if (!statusBarFlowHandoffCrossfade) {
            tvStatusClock.setAlpha(1f);
            View statusBar = findViewById(R.id.layout_status_bar);
            if (statusBar != null) statusBar.setAlpha(1f);
        }
        applyStatusBarTitleMarquee();
    }

    /** Prep status bar for reverse handoff — title swaps during reveal, not on changeScreen. */
    private void beginReverseStatusBarHandoff() {
        statusBarFlowHandoffCrossfade = true;
    }

    /** Fade status bar out on Back — pairs with reveal crossfade after flyer morph. */
    private void beginReverseStatusBarFadeOut() {
        beginReverseStatusBarHandoff();
        final View statusBar = findViewById(R.id.layout_status_bar);
        if (statusBar == null) return;
        statusBar.setVisibility(View.VISIBLE);
        statusBar.setAlpha(1f);
        final int gen = ++statusBarHandoffFadeGen;
        final long startMs = System.currentTimeMillis();
        final Runnable tick = new Runnable() {
            @Override
            public void run() {
                if (gen != statusBarHandoffFadeGen) return;
                float t = (System.currentTimeMillis() - startMs) / (float) STATUS_BAR_HANDOFF_FADE_MS;
                if (t >= 1f) {
                    statusBar.setAlpha(0f);
                    return;
                }
                float eased = 1f - (1f - t) * (1f - t);
                statusBar.setAlpha(1f - eased);
                statusBar.postOnAnimation(this);
            }
        };
        statusBar.postOnAnimation(tick);
    }

    /** Ease Flow status title in after flyer lands — avoids pop when changeScreen runs. */
    private void applyReverseStatusBarReveal(float eased) {
        View statusBar = findViewById(R.id.layout_status_bar);
        if (tvStatusClock == null || !statusBarFlowHandoffCrossfade) return;
        if (statusBar != null) {
            statusBar.setVisibility(View.VISIBLE);
            statusBar.setAlpha(eased);
        }
        String flowTitle = getString(R.string.status_flow);
        if (eased < 0.35f) {
            tvStatusClock.setText(getString(R.string.status_now_playing));
            tvStatusClock.setAlpha(1f);
            return;
        }
        float t = (eased - 0.35f) / 0.65f;
        float alpha = t * (2f - t);
        tvStatusClock.setText(flowTitle);
        tvStatusClock.setAlpha(alpha);
        if (eased >= 1f) {
            tvStatusClock.setAlpha(1f);
            if (statusBar != null) statusBar.setAlpha(1f);
            statusBarFlowHandoffCrossfade = false;
            applyStatusBarTitleMarquee();
        }
    }

    private String getStatusBarContextTitle() {
        switch (currentScreenState) {
            case STATE_MENU:
                return getString(R.string.status_home);
            case STATE_BROWSER: return browserStatusTitle != null ? browserStatusTitle : getString(R.string.status_library_main);
            case STATE_PLAYER: return getString(R.string.status_now_playing);
            case STATE_SETTINGS: return resolveSettingsSubTitle();
            case STATE_BLUETOOTH: return getString(R.string.status_bluetooth_scan);
            case STATE_WIFI: return getString(R.string.status_wifi_networks);
            case STATE_WIFI_KEYBOARD: return getKeyboardStatusBarTitle();
            case STATE_BRIGHTNESS: return getString(R.string.status_brightness);
            case STATE_STORAGE: return getString(R.string.status_storage);
            case STATE_WEBSERVER: return getString(R.string.status_pc_upload);
            case STATE_PODCASTS: return getString(R.string.status_podcasts);
            case STATE_FLOW: return getString(R.string.status_flow);
            case STATE_SOULSEEK:
                return browserStatusTitle != null && isGetMusicUnifiedUi()
                        ? browserStatusTitle : getString(R.string.status_soulseek);
            case STATE_DEEZER: return getString(R.string.status_deezer);
            case STATE_DEEZER_SETUP: return getString(R.string.status_deezer_setup);
            case STATE_APPS: return getString(R.string.status_apps);
            case STATE_MORE: return getString(R.string.path_more);
            case STATE_USB_STORAGE: return "USB Storage";
            default:
                if (mediaSuite != null) {
                    String mediaTitle = mediaSuite.statusTitleForState(currentScreenState);
                    if (mediaTitle != null && !mediaTitle.isEmpty()) return mediaTitle;
                }
                return getString(R.string.status_home);
        }
    }

