    private View rootViewForScreenState(int state) {
        if (state == STATE_MENU) return layoutMainMenu;
        if (state == STATE_PLAYER) return layoutPlayerMode;
        if (state == STATE_SETTINGS) return layoutSettingsMode;
        if (state == STATE_FLOW) return layoutFlowMode;
        if (state == STATE_BLUETOOTH) return layoutBluetoothMode;
        if (state == STATE_WIFI) return layoutWifiMode;
        if (state == STATE_WIFI_KEYBOARD) return layoutWifiKeyboard;
        if (state == STATE_BRIGHTNESS) return layoutBrightnessMode;
        if (state == STATE_STORAGE) return layoutStorageMode;
        if (state == STATE_WEBSERVER || state == STATE_DEEZER_SETUP) return layoutWebServerMode;
        if (state == MediaSuiteHost.STATE_VIDEO_PLAYER) return findViewById(R.id.layout_video_mode);
        if (state == MediaSuiteHost.STATE_PHOTO_VIEWER) return findViewById(R.id.layout_photo_viewer);
        if (ScreenTransitionMap.sameBrowserRoot(state)) return layoutBrowserMode;
        return null;
    }

    private void finalizeScreenVisibility(int state) {
        screenTransitionDeferHide = false;
        // Backdrop commit runs in coordinator complete — clear defer flag only.
        screenTransitionDeferBg = false;
        if (pendingDeferredHomeMenuRebuild && state == STATE_MENU) {
            pendingDeferredHomeMenuRebuild = false;
            buildHomeMenu();
            requestFirstHomeMenuFocus();
            updateHomeMenuPreview(focusedHomeMenuIndex);
        }
        if (screenTransitionOutgoingRoot != null) {
            screenTransitionOutgoingRoot.setVisibility(View.GONE);
            com.solar.launcher.ui.ScreenTransition.resetView(screenTransitionOutgoingRoot);
            screenTransitionOutgoingRoot = null;
        }
        View in = rootViewForScreenState(state);
        com.solar.launcher.ui.ScreenTransition.resetView(in);
        // #region agent log
        if (state == STATE_PLAYER) {
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("browserVis", layoutBrowserMode != null ? layoutBrowserMode.getVisibility() : -1);
                d.put("playerVis", layoutPlayerMode != null ? layoutPlayerMode.getVisibility() : -1);
                d.put("previewPaneVis", podcastPreviewPane != null ? podcastPreviewPane.getVisibility() : -1);
                d.put("podcastActive", playback.isPodcastActive());
                com.solar.launcher.DebugSessionLog.log("MainActivity.finalizeScreenVisibility",
                        "player layout finalized", "H-B-H-C", d);
            } catch (Exception ignored) {}
        }
        // #endregion
    }

    /** Push/pop on clipped settings list host. */
    private void drillSettingsForward(Runnable build) {
        ListDrillTransition.push(settingsMenuHost, build);
    }

    private void drillSettingsBack(Runnable build) {
        ListDrillTransition.pop(settingsMenuHost, build);
    }

    /** Push/pop on library browse list host. */
    private void drillBrowserForward(Runnable build) {
        ListDrillTransition.push(browserListHost, build);
    }

    private void drillBrowserBack(Runnable build) {
        ListDrillTransition.pop(browserListHost, build);
    }

    private void applyScreenChange(int state) {
        applyScreenChange(state, false);
    }

    private void applyScreenChange(int state, boolean deferOutgoingHide) {
        // #region agent log
        final long applyStartMs = System.currentTimeMillis();
        // #endregion
        if (currentScreenState == STATE_PLAYER && state != STATE_PLAYER) {
            flushPodcastResumeIfNeeded();
            pausePodcastBackgroundDownload();
            clearPlayerScrubCursorMode(false);
            // Keep stream cache while a persisted queue still references temps.
            if (!playback.hasAnyQueue()
                    && (!playback.isMusicActive() || state != STATE_SETTINGS)) {
                if (deferOutgoingHide) {
                    clockHandler.post(new Runnable() {
                        @Override
                        public void run() {
                            if (currentScreenState != STATE_PLAYER) purgeStreamTempFiles();
                        }
                    });
                } else {
                    purgeStreamTempFiles();
                }
            }
        }
        if (state != STATE_PLAYER) maybeRenamePodcastGrowingCache();

        SessionLifecycle.onLeaveScreen(this, currentScreenState, state);
        if (mediaSuite != null) {
            mediaSuite.onScreenExit(currentScreenState);
        }
        if (currentScreenState == STATE_FLOW && state != STATE_FLOW && state != STATE_PLAYER) {
            clearStaleFlowReturnHints(state);
        }
        if (state == STATE_FLOW && currentScreenState != STATE_FLOW && currentScreenState != STATE_PLAYER) {
            flowEntryReturnSnapshot = currentScreenState;
        }
        if (state == STATE_FLOW && currentScreenState == STATE_PLAYER && playback.isMusicActive()) {
            markFlowNowPlayingBackReturn();
        } else if (state == STATE_FLOW && currentScreenState != STATE_PLAYER && flowScreenHost != null) {
            // Menu/library Play-hold → Flow: Back exits to origin, not Now Playing.
            flowScreenHost.clearNowPlayingBackReturn();
        }
        if (state == STATE_PLAYER && currentScreenState != STATE_PLAYER) {
            if (currentScreenState == STATE_FLOW) {
                playerReturnScreen = STATE_FLOW;
                // #region agent log
                try {
                    org.json.JSONObject d = new org.json.JSONObject();
                    d.put("fromFlow", true);
                    d.put("pendingReturn", flowScreenHost != null && flowScreenHost.hasPendingPlayerReturn());
                    DebugSessionLog.log("MainActivity.changeScreen", "playerReturn=FLOW", "H-E", d);
                } catch (Exception ignored) {}
                // #endregion
            } else {
                playerReturnScreen = currentScreenState;
                if (currentScreenState == STATE_PODCASTS) {
                    playerReturnPodcastUiMode = podcastUiMode;
                }
            }
        }
        if (state == STATE_PLAYER && playback.isPodcastActive() && podcastDownloadPaused) {
            maybeResumePodcastDownload();
        }

        int safeFocusIndex = lastSettingsFocusIndex;
        final int leavingScreen = currentScreenState;
        if (deferOutgoingHide) {
            View outgoing = rootViewForScreenState(leavingScreen);
            View incoming = rootViewForScreenState(state);
            if (outgoing != null && outgoing != incoming) {
                screenTransitionDeferHide = true;
                screenTransitionOutgoingRoot = outgoing;
                screenTransitionDeferBg = true;
            }
        } else {
            screenTransitionDeferHide = false;
            screenTransitionOutgoingRoot = null;
            screenTransitionDeferBg = false;
        }
        if (state != STATE_SETTINGS) {
            // ponytail: keep settings sub-screen while on text keyboards — cleared on return.
            if (!(state == STATE_WIFI_KEYBOARD && isTextEntryKeyboardPurpose())) {
                settingsSubScreenKey = null;
                settingsSubScreenExtra = null;
            }
            hideThemeGalleryInterstitial();
            clearThemeGalleryPreview();
        }
        currentScreenState = state;
        refreshBlockingOverlayVisible();
        scheduleSoulseekSharePolicyRefresh();
        layoutMainMenu.setVisibility(state == STATE_MENU ? View.VISIBLE : View.GONE);
        if (state != STATE_MENU && layoutMainMenu != null) {
            layoutMainMenu.setVisibility(View.GONE);
        }
        layoutBrowserMode.setVisibility((state == STATE_BROWSER || state == STATE_PODCASTS || state == STATE_SOULSEEK || state == STATE_DEEZER || state == STATE_APPS || state == STATE_MORE
                || state == STATE_USB_STORAGE
                || state == MediaSuiteHost.STATE_RADIO || state == MediaSuiteHost.STATE_RADIO_FM_BROWSE
                || state == MediaSuiteHost.STATE_RADIO_NET_BROWSE || state == MediaSuiteHost.STATE_VIDEOS
                || state == MediaSuiteHost.STATE_PHOTOS) ? View.VISIBLE : View.GONE);
        if (state == STATE_BROWSER || state == STATE_PODCASTS || state == STATE_SOULSEEK || state == STATE_DEEZER
                || state == STATE_APPS || state == STATE_MORE || state == STATE_USB_STORAGE
                || state == MediaSuiteHost.STATE_RADIO || state == MediaSuiteHost.STATE_RADIO_FM_BROWSE
                || state == MediaSuiteHost.STATE_RADIO_NET_BROWSE || state == MediaSuiteHost.STATE_VIDEOS
                || state == MediaSuiteHost.STATE_PHOTOS) {
            resetBrowserListHost();
        }
        layoutPlayerMode.setVisibility(state == STATE_PLAYER ? View.VISIBLE : View.GONE);
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("state", state);
            d.put("leavingScreen", leavingScreen);
            d.put("browserVis", layoutBrowserMode != null ? layoutBrowserMode.getVisibility() : -1);
            d.put("playerVis", layoutPlayerMode != null ? layoutPlayerMode.getVisibility() : -1);
            d.put("settingsVis", layoutSettingsMode != null ? layoutSettingsMode.getVisibility() : -1);
            d.put("soulseekUiMode", soulseekUiMode);
            d.put("getMusicEmbedded", getMusicEmbeddedInDeezer);
            com.solar.launcher.DebugSessionLog.log("MainActivity.applyScreenChange", "layout visibility", "H-A-H-B-H-C", d);
        } catch (Exception ignored) {}
        // #endregion
        if (state == STATE_PLAYER) {
            if (layoutPlayerMode != null) {
                // #region agent log
                try {
                    org.json.JSONObject d = new org.json.JSONObject();
                    d.put("alphaBefore", layoutPlayerMode.getAlpha());
                    d.put("deferOutgoingHide", deferOutgoingHide);
                    d.put("leavingScreen", leavingScreen);
                    d.put("browserVis", layoutBrowserMode != null ? layoutBrowserMode.getVisibility() : -1);
                    d.put("playerVis", layoutPlayerMode.getVisibility());
                    d.put("previewPaneVis", podcastPreviewPane != null ? podcastPreviewPane.getVisibility() : -1);
                    d.put("podcastActive", playback.isPodcastActive());
                    DebugSessionLog.log("MainActivity.applyScreenChange", "player enter", "H-B-H-C", d);
                } catch (Exception ignored) {}
                // #endregion
                // Forward Flow handoff crossfades player in — don't flash static art before flyer lands.
                float playerAlpha = (skipFlowLayoutFade && leavingScreen == STATE_FLOW) ? 0f : 1f;
                layoutPlayerMode.setAlpha(playerAlpha);
            }
            // Browse/Deezer partial-play used to call applyScreenChange directly — hide source chrome.
            if (layoutBrowserMode != null) {
                layoutBrowserMode.setVisibility(View.GONE);
            }
            if (settingsPreviewPane != null) {
                settingsPreviewPane.setVisibility(View.GONE);
            }
            if (!FlowPlayerHandoff.isHandoffAnimating()
                    && !(skipFlowLayoutFade && leavingScreen == STATE_FLOW)) {
                if (layoutPlayerMode != null) layoutPlayerMode.setAlpha(1f);
                revealPlayerAlbumSlotAfterHandoff();
            }
            syncPlayerAlbumArt3dVisibility();
        }
        if (layoutFlowMode != null) {
            if (state == STATE_FLOW) {
                layoutFlowMode.setVisibility(View.VISIBLE);
                // #region agent log
                try {
                    org.json.JSONObject d = new org.json.JSONObject();
                    d.put("leavingScreen", leavingScreen);
                    d.put("skipFlowLayoutFade", skipFlowLayoutFade);
                    d.put("willFadeIn", !skipFlowLayoutFade && leavingScreen != STATE_FLOW);
                    DebugSessionLog.log("MainActivity.applyScreenChange", "flow enter", "H2", d);
                    Debug1cf0c7Log.log(this, "MainActivity.applyScreenChange", "flow enter", "H-E", d);
                } catch (Exception ignored) {}
                // #endregion
                if (skipFlowLayoutFade || leavingScreen == STATE_FLOW) {
                    // ponytail: reverse reveal may still be easing layout alpha — don't stomp mid-fade.
                    if (!FlowPlayerHandoff.isHandoffAnimating()) {
                        layoutFlowMode.setAlpha(1f);
                    }
                    skipFlowLayoutFade = false;
                } else if (screenTransitionDeferHide) {
                    // Root push/pop already animates layoutFlowMode — stacked fadeIn caused resetView cancel loop.
                    layoutFlowMode.setAlpha(1f);
                } else {
                    com.solar.launcher.flow.FlowScreenTransition.fadeInView(layoutFlowMode, null);
                }
            } else if (leavingScreen == STATE_FLOW) {
                // #region agent log
                try {
                    org.json.JSONObject d = new org.json.JSONObject();
                    d.put("targetState", state);
                    d.put("skipFlowLayoutFade", skipFlowLayoutFade);
                    com.solar.launcher.flow.FlowBackDebugLog.log(
                            "MainActivity.applyScreenChange", "leaving flow", "H-V2", d);
                } catch (Exception ignored) {}
                // #endregion
                if (skipFlowLayoutFade) {
                    if (state == STATE_PLAYER) {
                        // Forward handoff crossfades flowLayout alpha — keep visible until onHandoffComplete.
                        layoutFlowMode.setVisibility(View.VISIBLE);
                        layoutFlowMode.setAlpha(1f);
                    } else {
                        layoutFlowMode.setVisibility(View.GONE);
                        layoutFlowMode.setAlpha(1f);
                    }
                    skipFlowLayoutFade = false;
                } else if (state == STATE_MENU) {
                    if (!screenTransitionDeferHide) {
                        layoutFlowMode.setVisibility(View.GONE);
                        layoutFlowMode.setAlpha(1f);
                    }
                } else {
                    com.solar.launcher.flow.FlowScreenTransition.fadeOutView(layoutFlowMode, null);
                }
            } else {
                layoutFlowMode.setVisibility(View.GONE);
                layoutFlowMode.setAlpha(1f);
            }
        }
        if (state == STATE_PLAYER && playerTransport != null) {
            playerTransport.setHintVisible(false);
            playerTransport.setVisible(true);
        }
        if (state == MediaSuiteHost.STATE_VIDEO_PLAYER && videoTransport != null) {
            videoTransport.setHintVisible(false);
        }
        if (state == STATE_PLAYER) {
            refreshPlayerMarquee();
            syncPlayerAlbumArt3dVisibility();
            if (playback.isRadioActive() && mediaSuite != null) {
                mediaSuite.bindRadioNowPlayingUi();
            }
        }
        layoutSettingsMode.setVisibility(state == STATE_SETTINGS ? View.VISIBLE : View.GONE);
        layoutBluetoothMode.setVisibility(state == STATE_BLUETOOTH ? View.VISIBLE : View.GONE);
        layoutWifiMode.setVisibility(state == STATE_WIFI ? View.VISIBLE : View.GONE);
        layoutWifiKeyboard.setVisibility(state == STATE_WIFI_KEYBOARD ? View.VISIBLE : View.GONE);
        layoutBrightnessMode.setVisibility(state == STATE_BRIGHTNESS ? View.VISIBLE : View.GONE);
        layoutStorageMode.setVisibility(state == STATE_STORAGE ? View.VISIBLE : View.GONE);
        layoutWebServerMode.setVisibility((state == STATE_WEBSERVER || state == STATE_DEEZER_SETUP)
                ? View.VISIBLE : View.GONE);
        layoutVolumeOverlay.setVisibility(View.GONE);
        applyStatusBarTheme();
        if (state == STATE_MENU) {
            isPickingBackground = false;
            settingsBrowseFullWidth = false;
            applyFullWidthMenusLayout();
            applyPodcastBrowserLayout();
            if (layoutBrowserMode != null) layoutBrowserMode.setVisibility(View.GONE);
            // ponytail: animated Back — paint outgoing first; rebuild menu after slide, not before.
            if (shouldDeferHomeMenuRebuild(leavingScreen, deferOutgoingHide)) {
                pendingDeferredHomeMenuRebuild = true;
                refreshHomeMenuRowStyles();
                requestFirstHomeMenuFocus();
                updateHomeMenuPreview(focusedHomeMenuIndex);
            } else {
                buildHomeMenu();
                requestFirstHomeMenuFocus();
                updateHomeMenuPreview(focusedHomeMenuIndex);
            }
        }
        updateStatusBarTitle();
        updatePlaybackStatusIcon();
        if (!screenTransitionDeferBg) {
            updateScreenBackground(state);
        }
        if (state == STATE_BROWSER) {
            if (currentBrowserMode == BROWSER_ROOT || currentBrowserMode == BROWSER_FOLDER) {
                buildFileBrowserUI();
            } else if (currentBrowserMode == BROWSER_ARTISTS) {
                buildVirtualCategories("ARTIST");
            } else if (currentBrowserMode == BROWSER_ALBUMS) {
                buildVirtualCategories("ALBUM");
            } else if (currentBrowserMode == BROWSER_GENRES) {
                buildVirtualCategories("GENRE");
            } else if (currentBrowserMode == BROWSER_ARTIST_ALBUMS) {
                buildArtistAlbums();
            } else if (currentBrowserMode == BROWSER_PLAYLISTS) {
                buildPlaylistsUI();
            } else if (currentBrowserMode == BROWSER_DEEZER_PLAYLIST) {
                if (deezerPlaylistView != null) openDeezerPlaylistBrowse(deezerPlaylistView);
                else buildPlaylistsUI();
            } else if (currentBrowserMode == BROWSER_VIRTUAL_SONGS) {
                buildVirtualSongs();
            } else {
                currentBrowserMode = BROWSER_ROOT;
                buildFileBrowserUI();
            }
        } else if (state == STATE_PODCASTS) {
            if (podcastUiModeOnReturn >= 0) {
                restorePodcastUi(podcastUiModeOnReturn);
                podcastUiModeOnReturn = PODCAST_UI_RESTORE_NONE;
            } else {
                buildPodcastSearchUI();
            }
        } else if (state == STATE_FLOW) {
            // #region agent log
            long flowScreenStartMs = System.currentTimeMillis();
            boolean consumedPrepared = false;
            // #endregion
            if (flowScreenHost != null && flowLaunchRequest != null) {
                if (flowScreenHost.consumeReturnPrepared()) {
                    consumedPrepared = true;
                    flowScreenHost.requestCarouselFocus();
                } else if (flowScreenHost.hasPendingPlayerReturn()) {
                    flowScreenHost.restoreAfterPlayer();
                } else if (leavingScreen == STATE_PLAYER && !npToFlowHandoffLanding) {
                    flowScreenHost.restoreCarouselSession(flowLaunchRequest);
                    flowScreenHost.syncCarouselToNowPlayingIfActive();
                } else if (flowScreenHost.hasResidentCarousel(flowLaunchRequest)) {
                    flowScreenHost.resumeCarouselSession(flowLaunchRequest);
                } else {
                    flowScreenHost.open(flowLaunchRequest);
                }
            }
            // #region agent log
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("durationMs", System.currentTimeMillis() - flowScreenStartMs);
                d.put("consumedPrepared", consumedPrepared);
                d.put("leavingScreen", leavingScreen);
                d.put("skipFlowLayoutFade", skipFlowLayoutFade);
                d.put("npToFlowLanding", npToFlowHandoffLanding);
                d.put("handoffAnim", FlowPlayerHandoff.isHandoffAnimating());
                d.put("restoreCarousel", leavingScreen == STATE_PLAYER && !npToFlowHandoffLanding);
                DebugSessionLog.log("MainActivity.changeScreen", "STATE_FLOW branch", "H3", d);
            } catch (Exception ignored) {}
            // #endregion
        } else if (state == STATE_SOULSEEK) {
            if (isGetMusicUnifiedUi()
                    && (getMusicSearchInProgress || soulseekUiMode == SOULSEEK_UI_RESULTS)) {
                if (getMusicSearchInProgress || !getMusicEntries.isEmpty()) {
                    buildGetMusicResultsUI();
                } else {
                    buildSoulseekSearchUI();
                }
            } else if (!isGetMusicUnifiedUi()
                    && (soulseekUiMode == SOULSEEK_UI_UNAVAILABLE
                    || (!ConnectivityHelper.isReachPeerOk()
                            && ReachPeerConnectivity.state()
                                    == ReachPeerConnectivity.State.UNAVAILABLE))) {
                buildReachUnavailableUI();
            } else if (soulseekSearchInProgress || soulseekUiMode == SOULSEEK_UI_RESULTS) {
                buildSoulseekResultsUI();
            } else {
                buildSoulseekSearchUI();
            }
        } else if (state == STATE_DEEZER) {
            applyReachBrowseLayoutMode();
            if (deezerScreen != null) {
                deezerScreen.rebuildVisibleUi();
            } else {
                buildDeezerSearchUI();
            }
        } else if (state == STATE_APPS) {
            buildAppsLauncherUI();
        } else if (state == STATE_MORE) {
            buildMoreMenuUI();
        }
        if (state == STATE_BROWSER || state == STATE_SOULSEEK || state == STATE_DEEZER
                || state == STATE_PODCASTS || state == STATE_APPS || state == STATE_MORE) {
            applyPodcastBrowserLayout();
        }
        refreshBrowserPathBreadcrumb();
        if (state == STATE_SETTINGS) {
            applyFullWidthMenusLayout();
            lastSettingsFocusIndex = safeFocusIndex;
            if (SettingsScreens.THEMES.equals(settingsSubScreenKey)) {
                buildUnifiedThemesUI();
            } else if (SettingsScreens.THEME_VARIANT.equals(settingsSubScreenKey) && themeVariantEntry != null) {
                openThemeVariantBrowser(themeVariantEntry);
            } else if (SettingsScreens.ABOUT.equals(settingsSubScreenKey)) {
                buildAboutUI();
            } else if (SettingsScreens.DEBUG.equals(settingsSubScreenKey)) {
                buildDebugUI();
            } else if (SettingsScreens.FLOW.equals(settingsSubScreenKey)) {
                buildFlowSettingsUI();
            } else if (SettingsScreens.SYSTEM_UPDATE.equals(settingsSubScreenKey)) {
                buildUpdateSettingsUI();
            } else if (SettingsScreens.PLAYBACK.equals(settingsSubScreenKey)) {
                buildPlaybackSettingsUI();
            } else if (SettingsScreens.DEVICE.equals(settingsSubScreenKey)) {
                buildDeviceSettingsUI();
            } else if (SettingsScreens.CONNECTIONS.equals(settingsSubScreenKey)) {
                buildConnectionsSettingsUI();
            } else if (SettingsScreens.USB.equals(settingsSubScreenKey)) {
                buildUsbSettingsUI();
            } else if (SettingsScreens.LIBRARY.equals(settingsSubScreenKey)) {
                buildLibrarySettingsUI();
            } else if (SettingsScreens.LIBRARY_BROWSE.equals(settingsSubScreenKey)) {
                buildLibraryBrowseSettingsUI();
            } else if (SettingsScreens.MEDIA.equals(settingsSubScreenKey)) {
                buildMediaSettingsUI();
            } else if (SettingsScreens.POWER.equals(settingsSubScreenKey)) {
                buildPowerSettingsUI();
            } else if (SettingsScreens.RESET.equals(settingsSubScreenKey)) {
                buildResetSettingsUI();
            } else if (SettingsScreens.RADIO.equals(settingsSubScreenKey)) {
                if (com.solar.launcher.radio.RadioExperiment.isEnabled(prefs)) {
                    buildRadioSettingsUI();
                } else {
                    buildSettingsUI();
                }
            } else if (SettingsScreens.VIDEO.equals(settingsSubScreenKey)) {
                buildVideoSettingsUI();
            } else if (SettingsScreens.LANGUAGE.equals(settingsSubScreenKey)) {
                buildLanguageSettingsUI();
            } else if (SettingsScreens.DATETIME.equals(settingsSubScreenKey)) {
                buildDateTimeUI();
            } else {
                buildSettingsUI();
            }

        } else if (state == STATE_BLUETOOTH) {
            startBluetoothScan();
        } else if (state == STATE_WIFI) {
            startWifiScan();
        } else if (state == STATE_WIFI_KEYBOARD) {
            openKeyboard();
        } else if (state == STATE_BRIGHTNESS) {
            loadBrightnessUI();
        } else if (state == STATE_STORAGE) {
            loadStorageUI();
        } else if (state == STATE_WEBSERVER) {
            if (btnServerToggle != null) btnServerToggle.setVisibility(View.VISIBLE);
            startWebServerIfNeeded();
            updateWebServerUI();
            refreshY1ThemedActionButtons();
            if (btnServerToggle != null) btnServerToggle.requestFocus();
            // Wi-Fi IP can lag behind CONNECTED on API 17 — retry bind shortly.
            findViewById(android.R.id.content).postDelayed(new Runnable() {
                @Override public void run() {
                    if (!isServerRunning) {
                        startWebServerIfNeeded();
                        updateWebServerUI();
                    }
                }
            }, 1500);
        } else if (state == STATE_DEEZER_SETUP) {
            startWebServerForDeezerSetup();
            updateDeezerSetupUI();
            refreshY1ThemedActionButtons();
            findViewById(android.R.id.content).postDelayed(new Runnable() {
                @Override public void run() {
                    if (!isServerRunning) {
                        startWebServerForDeezerSetup();
                        updateDeezerSetupUI();
                    }
                }
            }, 1500);
        } else if (state == STATE_USB_STORAGE) {
            buildUsbStorageUI();
        }
        if (mediaSuite != null) {
            mediaSuite.onScreenEnter(state);
        }
        if (screenTransitionDeferHide && screenTransitionOutgoingRoot != null) {
            screenTransitionOutgoingRoot.setVisibility(View.VISIBLE);
            View incomingRoot = rootViewForScreenState(state);
            if (incomingRoot != null && incomingRoot != screenTransitionOutgoingRoot) {
                // ponytail: hide incoming during build — coordinator reveals on first anim frame.
                incomingRoot.setVisibility(View.INVISIBLE);
            }
        }
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("state", state);
            d.put("deferOutgoingHide", deferOutgoingHide);
            d.put("applyMs", System.currentTimeMillis() - applyStartMs);
            d.put("deferBg", screenTransitionDeferBg);
            com.solar.launcher.ui.TransitionPerfLog.log("MainActivity.applyScreenChange", "done", "A", d);
        } catch (Exception ignored) {}
        // #endregion
        updateVideoStatusBarPolicy();
        updateNetworkRescanLoop();
    }

    /** Hide status bar during video; restore when leaving or when hold-Back menu is open. */
    private void updateVideoStatusBarPolicy() {
        View statusBar = findViewById(R.id.layout_status_bar);
        if (statusBar == null) return;
        boolean onVideo = currentScreenState == MediaSuiteHost.STATE_VIDEO_PLAYER;
        boolean ctxOpen = themedContextMenu != null && themedContextMenu.isShowing();
        statusBar.setVisibility(onVideo && !ctxOpen ? View.GONE : View.VISIBLE);
    }

    public void mediaSetStatusBarVisible(boolean visible) {
        View statusBar = findViewById(R.id.layout_status_bar);
        if (statusBar != null) statusBar.setVisibility(visible ? View.VISIBLE : View.GONE);
    }

    private void loadBrightnessUI() {
        try {
            currentSystemBrightness = Settings.System.getInt(getContentResolver(), Settings.System.SCREEN_BRIGHTNESS,
                    255);
        } catch (Exception e) {
        }
        pbBrightness.setProgress(currentSystemBrightness);
        int percent = (int) (((float) currentSystemBrightness / 255.0f) * 100);
        tvBrightnessVal.setText(percent + "%");
    }

    private void updateBrightness(int newBrightness) {
        currentSystemBrightness = newBrightness;
        if (pbBrightness != null) pbBrightness.setProgress(currentSystemBrightness);
        int percent = (int) (((float) currentSystemBrightness / 255.0f) * 100);
        if (tvBrightnessVal != null) tvBrightnessVal.setText(percent + "%");

        try {
            Settings.System.putInt(getContentResolver(), Settings.System.SCREEN_BRIGHTNESS_MODE,
                    Settings.System.SCREEN_BRIGHTNESS_MODE_MANUAL);
            Settings.System.putInt(getContentResolver(), Settings.System.SCREEN_BRIGHTNESS, currentSystemBrightness);
            WindowManager.LayoutParams layoutParams = getWindow().getAttributes();
            layoutParams.screenBrightness = currentSystemBrightness / 255.0f;
            getWindow().setAttributes(layoutParams);
        } catch (Exception e) {
        }
    }

    private void adjustContextBrightness(boolean up) {
        currentSystemBrightness = up
                ? Math.min(255, currentSystemBrightness + 15)
                : Math.max(10, currentSystemBrightness - 15);
        updateBrightness(currentSystemBrightness);
        if (themedContextMenu != null && contextMenuInVolumeSlider) {
            themedContextMenu.updateBrightnessSlider(currentSystemBrightness, 255);
        }
    }

    // 💡 [수정] 기존 막대바를 숨기고 우리가 만든 원형 차트를 동적으로 띄워주는 로직
    // 💡 [수정] 스토리지 상세 정보 텍스트 적용
    // 💡 [완벽 수정] 스토리지 용량 계산 에러(오버플로우) 방지 및 진짜 테마 색상 적용
    private void loadStorageUI() {
        try {
            android.os.StatFs stat = new android.os.StatFs("/storage/sdcard0");

            // 🚀 [버그 1 해결] 기기 용량이 클 때 숫자가 폭발(오버플로우)해서 에러가 나는 것을 막기 위해 (long)으로 강제 변환하여 계산합니다!
            long blockSize = (long) stat.getBlockSize();
            long total = ((long) stat.getBlockCount() * blockSize) / (1024 * 1024);
            long free = ((long) stat.getAvailableBlocks() * blockSize) / (1024 * 1024);
            long used = total - free;

            if (pbStorage != null) pbStorage.setVisibility(View.GONE);

            LinearLayout storageLayout = findViewById(R.id.layout_storage_mode);
            PieChartView pieChart = (PieChartView) storageLayout.findViewWithTag("pie_chart");

            if (pieChart == null) {
                pieChart = new PieChartView(this);
                pieChart.setTag("pie_chart");

                // 🚀 [버그 2 해결] 차트가 너무 커서 아래 글씨를 화면 밖으로 밀어내지 않도록 크기를 140dp로 최적화합니다.
                int size = (int)(140 * getResources().getDisplayMetrics().density);
                LinearLayout.LayoutParams lp = new LinearLayout.LayoutParams(size, size);
                lp.setMargins(0, 0, 0, 30);
                pieChart.setLayoutParams(lp);

                storageLayout.addView(pieChart, 1);
            }

            // 🚀 [버그 3 해결] 밋밋한 흰색(글자색) 대신, 테마의 진짜 강조 색상(버튼 포커스 색상)을 뽑아와서 투명도를 뺀 원색으로 칠합니다!
            int themeColor = ThemeManager.getProgressColor();
            pieChart.setStorageData(used, total, themeColor);

            // 텍스트 정보 세팅 및 화면 강제 노출
            tvStorageDetails.setText("Total Capacity :  " + total + " MB\nUsed Space :  " + used + " MB\nFree Space :  " + free + " MB");
            tvStorageDetails.setGravity(android.view.Gravity.CENTER);
            tvStorageDetails.setLineSpacing(15f, 1f);
            tvStorageDetails.setVisibility(View.VISIBLE);

        } catch (Exception e) {
            tvStorageDetails.setText("Storage Error: Failed to calculate space.");
            tvStorageDetails.setVisibility(View.VISIBLE);
        }
    }
    private static final long CONTEXT_MENU_CLICK_SUPPRESS_MS = 1000;

    private void handleCenterShortClick() {
        if (themedContextMenu != null && themedContextMenu.isShowing()) return;
        if (System.currentTimeMillis() < suppressListClickUntil) return;
        // #region agent log
        if (MediaSuiteHost.isMediaSuiteState(currentScreenState)) {
            try {
                View fc = getCurrentFocus();
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("screen", currentScreenState);
                d.put("focusNull", fc == null);
                d.put("focusClass", fc != null ? fc.getClass().getSimpleName() : "");
                d.put("listVis", listVirtualSongs != null && listVirtualSongs.getVisibility() == View.VISIBLE);
                d.put("browserChildCount", containerBrowserItems != null ? containerBrowserItems.getChildCount() : -1);
                DebugAgentLog.log(this, "MainActivity.handleCenterShortClick", "media center", "H-C", d);
            } catch (Exception ignored) {}
        }
        // #endregion
        if (currentScreenState == STATE_WIFI_KEYBOARD) {
            handleKeyboardInput();
        } else if (currentScreenState == STATE_MENU) {
            clickFeedback();
            if (focusedHomeMenuIndex >= 0 && focusedHomeMenuIndex < homeMenuEntries.size()) {
                onHomeMenuActivate(homeMenuEntries.get(focusedHomeMenuIndex).id);
            }
        } else if (currentScreenState != STATE_BRIGHTNESS && currentScreenState != STATE_STORAGE
                && currentScreenState != STATE_PLAYER) {
            if (currentScreenState == STATE_SETTINGS && SettingsScreens.HOME.equals(settingsSubScreenKey)) {
                View c = getCurrentFocus();
                if (c != null) {
                    if (System.currentTimeMillis() < suppressListClickUntil) return;
                    c.performClick();
                }
                return;
            }
            if (currentScreenState == STATE_SETTINGS && isThemeListActive()) {
                clickFeedback();
                ThemeBrowser.Row row = themeBrowserFocusedRow();
                // #region agent log
                try {
                    org.json.JSONObject d = new org.json.JSONObject();
                    d.put("rowNull", row == null);
                    d.put("focus", themeBrowserFocus);
                    d.put("rowCount", themeBrowserRows.size());
                    if (row != null) d.put("kind", row.kind);
                    DebugAgentLog.log(this, "MainActivity.handleCenterShortClick",
                            "theme row activate", "H-SEL", d);
                } catch (Exception ignored) {}
                // #endregion
                if (row != null) onThemeBrowserRowClick(row);
                return;
            }
            if (currentScreenState == STATE_SETTINGS
                    && SettingsScreens.SOULSEEK_CHAT_ROOM_WALL.equals(settingsSubScreenKey)
                    && soulseekConversationHost != null
                    && soulseekConversationHost.getVisibility() == View.VISIBLE
                    && listConversationThread != null) {
                if (performConversationHeaderClickIfFocused()) return;
                clickFeedback();
                int pos = listConversationThread.getSelectedItemPosition();
                if (pos < 0 && listConversationThread.getAdapter() != null
                        && listConversationThread.getAdapter().getCount() > 0) {
                    pos = listConversationThread.getAdapter().getCount() - 1;
                }
                if (listConversationThread.getAdapter() == null
                        || listConversationThread.getAdapter().getCount() == 0
                        || (pos >= 0 && isRoomNewMessagePosition(pos))) {
                    openSoulseekRoomWallCompose();
                } else if (pos >= 0) {
                    openReachRoomMessageContextMenu(pos);
                }
                return;
            }
            if (currentScreenState == STATE_SETTINGS
                    && (SettingsScreens.SOULSEEK_MESSAGES_THREAD.equals(settingsSubScreenKey)
                    || SettingsScreens.SOULSEEK_CHAT_ROOM_THREAD.equals(settingsSubScreenKey)
                    || isSolarDevelopmentThreadActive())
                    && soulseekConversationHost != null
                    && soulseekConversationHost.getVisibility() == View.VISIBLE
                    && listConversationThread != null) {
                if (performConversationHeaderClickIfFocused()) return;
                clickFeedback();
                int pos = listConversationThread.getSelectedItemPosition();
                if (pos < 0 && listConversationThread.getAdapter() != null
                        && listConversationThread.getAdapter().getCount() > 0) {
                    pos = listConversationThread.getAdapter().getCount() - 1;
                }
                if (listConversationThread.getAdapter() == null
                        || listConversationThread.getAdapter().getCount() == 0
                        || (pos >= 0 && isConversationNewMessagePosition(pos))) {
                    if (SettingsScreens.SOULSEEK_CHAT_ROOM_THREAD.equals(settingsSubScreenKey)) {
                        openSoulseekRoomCompose();
                    } else {
                        openSoulseekMessageCompose(soulseekMessagePeer);
                    }
                } else if (pos >= 0) {
                    contextReachMessageIsRoom =
                            SettingsScreens.SOULSEEK_CHAT_ROOM_THREAD.equals(settingsSubScreenKey);
                    openReachMessageContextMenu(pos);
                }
                return;
            }
            if (currentScreenState == STATE_BLUETOOTH && !isBluetoothListFocusValid()) {
                restoreBluetoothListFocus(null, false);
            }
            View c = getCurrentFocus();
            if (c != null) {
                if (System.currentTimeMillis() < suppressListClickUntil) return;
                c.performClick();
            }
        }
    }

    @Override
    public boolean dispatchKeyEvent(KeyEvent event) {
        resetInactivityTimer();
        if (themedContextMenu != null && themedContextMenu.isEnterExitAnimating()
                && event.getAction() == KeyEvent.ACTION_DOWN) {
            return true;
        }
        if ((ScreenTransition.isAnimating() || ListDrillTransition.isAnimating()
                || FlowPlayerHandoff.isHandoffAnimating())
                && event.getAction() == KeyEvent.ACTION_DOWN
                && !Y1InputKeys.isBackKey(event.getKeyCode())) {
            // #region agent log
            if (Y1InputKeys.isWheelKey(event.getKeyCode()) || Y1InputKeys.isVolumeUpKey(event.getKeyCode())
                    || Y1InputKeys.isVolumeDownKey(event.getKeyCode())) {
                try {
                    org.json.JSONObject d = new org.json.JSONObject();
                    d.put("keyCode", event.getKeyCode());
                    d.put("screen", currentScreenState);
                    d.put("screenTrans", ScreenTransition.isAnimating());
                    d.put("listDrill", ListDrillTransition.isAnimating());
                    d.put("flowHandoff", FlowPlayerHandoff.isHandoffAnimating());
                    d.put("reverseHandoff", reverseHandoffInProgress);
                    com.solar.launcher.flow.FlowBackDebugLog.log(
                            "MainActivity.dispatchKeyEvent", "volume blocked by anim", "H-V1", d);
                } catch (Exception ignored) {}
            }
            // #endregion
            return true;
        }
        // ponytail: Y1 wheel OK is often KEYCODE_MEDIA_PLAY_PAUSE — treat as center while context menu is open
        if (themedContextMenu != null && themedContextMenu.isShowing()
                && isCenterKey(event.getKeyCode())) {
            if (isWakingKeyEvent(event)) return true;
            if (event.getAction() == KeyEvent.ACTION_DOWN) return trackCenterKeyDown(event, true);
            if (event.getAction() == KeyEvent.ACTION_UP) return handleCenterKeyUp(event, true);
            return true;
        }
        // Center/OK activates focus; Play/Pause is transport (except keyboard — charset/OK there).
        if (isCenterKey(event.getKeyCode())) {
            if (isWakingKeyEvent(event)) return true;
            boolean fromMenu = themedContextMenu != null && themedContextMenu.isShowing();
            if (event.getAction() == KeyEvent.ACTION_DOWN) return trackCenterKeyDown(event, fromMenu);
            if (event.getAction() == KeyEvent.ACTION_UP) return handleCenterKeyUp(event, fromMenu);
            return true;
        }
        if (currentScreenState == STATE_WIFI_KEYBOARD && isMediaPlayPauseKey(event.getKeyCode())) {
            if (event.getAction() == KeyEvent.ACTION_DOWN) {
                return onKeyDown(event.getKeyCode(), event);
            }
            if (event.getAction() == KeyEvent.ACTION_UP) {
                return onKeyUp(event.getKeyCode(), event);
            }
            return true;
        }
        if (themedContextMenu != null && themedContextMenu.isShowing()) {
            if (event.getAction() == KeyEvent.ACTION_DOWN) {
                return onKeyDown(event.getKeyCode(), event);
            }
            if (event.getAction() == KeyEvent.ACTION_UP) {
                return onKeyUp(event.getKeyCode(), event);
            }
            return true;
        }
        // ponytail: intercept before ListView DPAD handling — see handleReachSettingsWheelKeyDown.
        if (handleReachSettingsWheelKeyDown(event.getKeyCode(), event)) return true;
        // #region agent log
        if (event.getAction() == KeyEvent.ACTION_DOWN && currentScreenState == STATE_PLAYER
                && (Y1InputKeys.isWheelKey(event.getKeyCode())
                || Y1InputKeys.isVolumeUpKey(event.getKeyCode())
                || Y1InputKeys.isVolumeDownKey(event.getKeyCode()))) {
            try {
                org.json.JSONObject d = new org.json.JSONObject();
                d.put("keyCode", event.getKeyCode());
                d.put("ctxMenu", themedContextMenu != null && themedContextMenu.isShowing());
                d.put("volOnly", contextMenuVolumeOnly);
                d.put("scrubActive", playerScrubCursorActive);
                d.put("flowVis", layoutFlowMode != null ? layoutFlowMode.getVisibility() : -1);
                d.put("flowAlpha", layoutFlowMode != null ? layoutFlowMode.getAlpha() : -1f);
                d.put("playerVis", layoutPlayerMode != null ? layoutPlayerMode.getVisibility() : -1);
                d.put("handoffAnim", FlowPlayerHandoff.isHandoffAnimating());
                View focus = getCurrentFocus();
                d.put("focusClass", focus != null ? focus.getClass().getSimpleName() : "null");
                com.solar.launcher.flow.FlowBackDebugLog.log(
                        "MainActivity.dispatchKeyEvent", "player volume key→super", "H-V2", d);
            } catch (Exception ignored) {}
        }
        // #endregion
        return super.dispatchKeyEvent(event);
    }

    private static boolean isCenterKey(int keyCode) {
        return Y1InputKeys.isCenterKey(keyCode);
    }

    private boolean isWakingKeyEvent(KeyEvent event) {
        PowerManager pm = (PowerManager) getSystemService(Context.POWER_SERVICE);
        boolean isScreenOn = true;
        try {
            if (android.os.Build.VERSION.SDK_INT >= 20) isScreenOn = pm.isInteractive();
            else isScreenOn = pm.isScreenOn();
        } catch (Exception ignored) {}
        return !isScreenOn || ((event.getFlags() & KeyEvent.FLAG_WOKE_HERE) != 0)
                || (System.currentTimeMillis() - lastScreenOnTime < 500);
    }

    // 💡 [추가] 과부하 방지용 타이머 변수
    private long lastClickTime = 0;

    // 💡 앱 자체의 억지 소리 발생 코드를 완전히 삭제합니다! (기기 하드웨어 소리만 사용)
    private void clickFeedback() {
        long now = System.currentTimeMillis();

        // 🚀 [UI 멈춤 완벽 차단] 0.03초 이내에 연속으로 들어온 휠 신호는 진동 모터를 울리지 않고 생략합니다!
        // 이 방어막 하나가 빠른 휠 스크롤 시 화면 딜레이를 80% 이상 없애줍니다.
        if (now - lastClickTime < 30) return;
        lastClickTime = now;

        try {
            if (isVibrationEnabled) {
                Vibrator v = (Vibrator) getSystemService(Context.VIBRATOR_SERVICE);
                if (v != null)
                    v.vibrate(20); // 🚀 진동 길이도 30 -> 20으로 줄여서 모터가 더 빨리 쉬게 만듭니다.
            }
        } catch (Exception e) {
        }
    }

    private boolean isConversationNewMessagePosition(int listPosition) {
        if (listConversationThread == null
                || !(listConversationThread.getAdapter() instanceof ConversationThreadAdapter)) {
            return false;
        }
        int headerCount = conversationHeaderOffset();
        return listPosition == headerCount + listConversationThread.getAdapter().getCount() - 1;
    }

    /** List position for a conversation adapter index (excludes header rows). */
    private int conversationAdapterListPosition(int adapterIndex) {
        return conversationHeaderOffset() + adapterIndex;
    }

    private String getFocusedReachPeerName() {
        View c = getCurrentFocus();
        if (c != null && c.getTag(ReachMessageRow.TAG_PEER) instanceof String) {
            return ((String) c.getTag(ReachMessageRow.TAG_PEER)).trim();
        }
        return null;
    }

    private String getFocusedReachRoomName() {
        if (!SettingsScreens.SOULSEEK_CHAT_ROOMS.equals(settingsSubScreenKey)) return null;
        if (reachChatRoomsAdapter == null) return null;
        int sel = reachChatRoomsAdapter.getSelectedPosition();
        if (sel < 0) return null;
        SoulseekWire.RoomEntry entry = reachChatRoomsAdapter.roomAt(sel);
        return entry != null && entry.name != null ? entry.name.trim() : null;
    }

    private void openReachMessageContextMenu(int messageListPosition) {
        if (!(listConversationThread.getAdapter() instanceof ConversationThreadAdapter)) return;
        int adapterIndex = messageListPosition - conversationHeaderOffset();
        if (adapterIndex < 0) return;
        ConversationThreadAdapter ad = (ConversationThreadAdapter) listConversationThread.getAdapter();
        ConversationDisplayBuilder.Entry entry = ad.getEntryAt(adapterIndex);
        if (entry == null || entry.message == null || entry.message.statusEvent) return;
        contextReachMessagePosition = adapterIndex;
        contextReachPeerUser = contextReachMessageIsRoom
                ? (entry.message.peer != null ? entry.message.peer : "")
                : soulseekMessagePeer;
        if (themedContextMenu != null && themedContextMenu.isShowing()) {
            pushContextReachMessageTier(adapterIndex);
            return;
        }
        showThemedContextMenu();
    }

    private boolean maybeAutoOpenReachContextTier() {
        if (isConversationThreadActive() && listConversationThread != null) {
            int pos = listConversationThread.getSelectedItemPosition();
            if (pos >= 0 && !isConversationNewMessagePosition(pos)) {
                contextReachMessageIsRoom =
                        SettingsScreens.SOULSEEK_CHAT_ROOM_THREAD.equals(settingsSubScreenKey);
                pushContextReachMessageTier(pos - conversationHeaderOffset());
                return true;
            }
        }
        if (currentScreenState == STATE_SETTINGS
                && SettingsScreens.SOULSEEK_MESSAGES.equals(settingsSubScreenKey)) {
            String peer = getFocusedReachPeerName();
            if (peer != null) {
                pushContextReachInboxTier(peer);
                return true;
            }
        }
        if (currentScreenState == STATE_SETTINGS
                && SettingsScreens.SOULSEEK_FIND_REACH.equals(settingsSubScreenKey)) {
            String peer = getFocusedReachPeerName();
            if (peer != null) {
                pushContextReachPeerTier(peer, null);
                return true;
            }
        }
        if (currentScreenState == STATE_SETTINGS
                && SettingsScreens.SOULSEEK_CHAT_ROOMS.equals(settingsSubScreenKey)) {
            String room = getFocusedReachRoomName();
            if (room != null && !room.isEmpty()) {
                pushContextReachChatRoomTier(room);
                return true;
            }
        }
        return false;
    }

    private void pushContextReachMessageTier(int messagePosition) {
        if (!(listConversationThread.getAdapter() instanceof ConversationThreadAdapter)) return;
        ConversationThreadAdapter ad = (ConversationThreadAdapter) listConversationThread.getAdapter();
        ConversationDisplayBuilder.Entry entry = ad.getEntryAt(messagePosition);
        if (entry == null || entry.message == null || entry.message.statusEvent) return;
        contextReachMessagePosition = messagePosition;
        contextReachPeerUser = contextReachMessageIsRoom
                ? (entry.message.peer != null ? entry.message.peer : "")
                : soulseekMessagePeer;
        pushContextMenuTier("reach_msg");
        rebuildContextReachMessageTier(true);
    }

    private void pushContextReachInboxTier(final String peer) {
        if (peer == null || peer.trim().isEmpty()) return;
        contextReachPeerUser = peer.trim();
        contextReachMessagePosition = -1;
        contextReachPeerInfo = null;
        pushContextMenuTier("reach_inbox");
        rebuildContextReachInboxTier(true);
    }

    private void pushContextReachChatRoomTier(final String room) {
        if (room == null || room.trim().isEmpty()) return;
        contextReachChatRoomName = room.trim();
        contextReachPeerUser = null;
        contextReachMessagePosition = -1;
        pushContextMenuTier("reach_chat_room");
        rebuildContextReachChatRoomTier(true);
    }

    private String contextReachChatRoomName = "";

    private void rebuildContextReachChatRoomTier(boolean focusList) {
        final String room = contextReachChatRoomName;
        if (room == null || room.isEmpty()) return;
        java.util.ArrayList<String> labels = new java.util.ArrayList<String>();
        java.util.ArrayList<String> states = new java.util.ArrayList<String>();
        java.util.ArrayList<Boolean> headers = new java.util.ArrayList<Boolean>();
        java.util.ArrayList<Runnable> actions = new java.util.ArrayList<Runnable>();

        labels.add(room);
        states.add(null);
        headers.add(Boolean.TRUE);
        actions.add(null);

        labels.add(getString(R.string.soulseek_open_chat_room));
        states.add(null);
        headers.add(Boolean.FALSE);
        actions.add(new Runnable() {
            @Override
            public void run() {
                dismissThemedContextMenu();
                SoulseekClient client = ensureSoulseekClient();
                if (client != null) client.joinRoom(room);
                buildSoulseekChatRoomUI(room);
            }
        });

        if (!ReachCommunityRooms.isProtected(room)) {
            labels.add(getString(R.string.soulseek_leave_chat_room));
            states.add(null);
            headers.add(Boolean.FALSE);
            actions.add(new Runnable() {
                @Override
                public void run() {
                    dismissThemedContextMenu();
                    SoulseekClient client = ensureSoulseekClient();
                    if (client != null) client.leaveRoom(room);
                    SoulseekRoomPrefs.markLeft(MainActivity.this, prefs, room);
                    if (reachChatRoomsAdapter != null) {
                        String query = reachChatRoomsAdapter.getSearchQuery();
                        if (query != null && !query.isEmpty()) {
                            runReachChatRoomSearch(query, ++reachChatRoomsSearchGen);
                        } else {
                            reachChatRoomsAdapter.replaceRooms(
                                    ReachCommunityRooms.pinInnioasis(prefs,
                                            ReachCommunityRooms.defaultRoomList()));
                            focusReachChatRoomsBrowse(reachChatRoomsAdapter);
                        }
                    }
                    Toast.makeText(MainActivity.this,
                            getString(R.string.soulseek_left_chat_room, room),
                            Toast.LENGTH_SHORT).show();
                }
            });
        }

        showContextMenuTierInPlace(room, labels, states, null, headers, actions, focusList);
    }

    private void pushContextReachPeerTier(final String username,
            final SoulseekUserDirectory.UserInfo cachedInfo) {
        if (username == null || username.trim().isEmpty()) return;
        contextReachPeerUser = username.trim();
        contextReachMessagePosition = -1;
        contextReachPeerInfo = cachedInfo;
        pushContextMenuTier("reach_peer");
        if (cachedInfo != null) {
            rebuildContextReachPeerTier(true);
        } else {
            SoulseekUserDirectory.watch(ensureSoulseekClient(), contextReachPeerUser,
                    new SoulseekUserDirectory.Callback() {
                        @Override
                        public void onUserInfo(final SoulseekUserDirectory.UserInfo info) {
                            runOnUiThread(new Runnable() {
                                @Override
                                public void run() {
                                    contextReachPeerInfo = info;
                                    if ("reach_peer".equals(contextMenuTopTier())) {
                                        rebuildContextReachPeerTier(false);
                                    }
                                }
                            });
                        }

                        @Override
                        public void onError(final String reason) {
                            runOnUiThread(new Runnable() {
                                @Override
                                public void run() {
                                    if ("reach_peer".equals(contextMenuTopTier())) {
                                        rebuildContextReachPeerTier(false);
                                    }
                                }
                            });
                        }
                    });
            rebuildContextReachPeerTier(true);
        }
    }

    private void pushContextReachReactTier(final String quoteText) {
        if (quoteText == null || quoteText.trim().isEmpty()) return;
        contextReachReactQuote = quoteText.trim();
        pushContextMenuTier("reach_react");
        rebuildContextReachReactTier(true);
    }

    private String buildReachMessageDetailText(ConversationDisplayBuilder.Entry entry) {
        if (entry == null) return "";
        StringBuilder detail = new StringBuilder();
        if (entry.isReply) detail.append("↳ ");
        detail.append(entry.displayText);
        if (!entry.reactionLines.isEmpty()) {
            detail.append("\n");
            for (int i = 0; i < entry.reactionLines.size(); i++) {
                if (i > 0) detail.append("\n");
                detail.append(entry.reactionLines.get(i));
            }
        }
        if (entry.timestamp != null && !entry.timestamp.isEmpty()) {
            detail.append("\n").append(entry.timestamp);
        }
        return detail.toString();
    }

    /** Scrollable context-modal body for inbound developer PM alerts and dev-thread messages. */
    private String buildSolarDeveloperPmDetailText(String body, String fromDev) {
        StringBuilder detail = new StringBuilder(getString(R.string.solar_developer_pm_from_label));
        String visible = body != null ? SolarDeveloperAccounts.displayBody(body.trim()) : "";
        if (!visible.isEmpty()) {
            detail.append('\n').append(visible);
        }
        return detail.toString();
    }

    private String buildSolarDeveloperPmDetailText(String body) {
        return buildSolarDeveloperPmDetailText(body, contextReachPmFromDev);
    }

    /** Reach PM notification / inbox context-modal body with sender on the first line. */
    private String buildReachPmDetailText(String peer, String body) {
        StringBuilder detail = new StringBuilder();
        if (peer != null && !peer.trim().isEmpty()) {
            detail.append(peer.trim());
        }
        if (body != null && !body.trim().isEmpty()) {
            if (detail.length() > 0) detail.append('\n');
            detail.append(body.trim());
        }
        return detail.toString();
    }

