    static boolean isAudioFile(File f) {
        if (f == null || !f.isFile())
            return false;
        String name = f.getName().toLowerCase();
        return name.endsWith(".mp3") || name.endsWith(".flac") || name.endsWith(".wav") || name.endsWith(".ogg")
                || name.endsWith(".m4a") || name.endsWith(".aac") || name.endsWith(".ape") || name.endsWith(".wma");
    }

    private boolean isApkFile(File f) {
        if (f == null || !f.isFile())
            return false;
        return f.getName().toLowerCase().endsWith(".apk");
    }

    private boolean isImageFile(File f) {
        if (f == null || !f.isFile())
            return false;
        String name = f.getName().toLowerCase();
        return name.endsWith(".jpg") || name.endsWith(".jpeg") || name.endsWith(".png");
    }

    // 💡 하위 폴더까지 뒤져서 음악 파일의 '경로'만 모두 수집해 오는 함수
    private void collectAudioFiles(File file, List<String> paths) {
        if (file.isDirectory()) {
            File[] files = file.listFiles();
            if (files != null) {
                for (File f : files) {
                    collectAudioFiles(f, paths); // 폴더면 파고들기
                }
            }
        } else if (isAudioFile(file)) {
            paths.add(file.getAbsolutePath()); // 음악 파일이면 명단에 추가!
        }
    }

    // 💡 1. Incremental library scan — SQLite cache + ID3 only for new/changed files.
    private static final class LibraryScanResolved {
        SongItem item;
        String metaKey;
    }

    /** Shared worker for onCreate, manual scan, and post-download refresh. */
    private void startLibraryScan(final boolean userInitiated) {
        if (libraryScanRunning) return;
        if (isUsbMassStorageUiLocked()) return;
        libraryScanRunning = true;
        isCustomScanning = customLibrary.isEmpty();
        libraryScanTrackCount = 0;
        final int gen = libraryScanGen;
        activeLibraryScanGen = gen;
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("gen", gen);
            d.put("userInitiated", userInitiated);
            d.put("libEmpty", customLibrary.isEmpty());
            Debug898913Log.logAlways("MainActivity.startLibraryScan", "scan started", "H1", d);
        } catch (Exception ignored) {}
        // #endregion
        runOnUiThread(new Runnable() {
            @Override
            public void run() {
                acquireBlockingOverlay(OVERLAY_LIB_SCAN, getString(R.string.library_scanning));
            }
        });
        new Thread(new Runnable() {
            @Override
            public void run() {
                runLibraryScanWorker(gen, userInitiated);
            }
        }, "LibraryScan").start();
    }

    private void runLibraryScanWorker(final int gen, final boolean userInitiated) {
        final MusicLibraryStore store = MusicLibraryStore.getInstance(getApplicationContext());
        if (customLibrary.isEmpty()) {
            java.util.List<MusicLibraryStore.Track> cached = store.loadAll();
            if (libraryScanGen != gen) {
                abortLibraryScanWorker(gen);
                return;
            }
            if (!cached.isEmpty()) {
                applyCachedTracks(cached);
                postLibraryCacheHydrated(gen);
            }
        }
        if (!userInitiated && tryFinishScanFromFreshCache(gen, userInitiated)) {
            return;
        }
        final java.util.HashSet<String> seenPaths = MusicLibraryStore.newKeepSet();
        final java.util.ArrayList<SongItem> scanned = new java.util.ArrayList<SongItem>();
        final int progressInterval = 25;
        LibraryScanner.Callback scanCb = new LibraryScanner.Callback() {
            @Override public boolean isCancelled() { return libraryScanGen != gen; }
            @Override public void onProgress(int resolvedCount) {
                libraryScanTrackCount = resolvedCount;
                postLibraryScanProgress(gen, resolvedCount);
            }
            @Override public int progressInterval() { return progressInterval; }
        };
        long tScan0 = System.currentTimeMillis();
        LibraryScanner.ScanResult result = LibraryScanner.scan(rootFolder, store,
                blacklist, prefs, seenPaths, scanCb);
        if (libraryScanGen != gen) {
            abortLibraryScanWorker(gen);
            return;
        }
        scanned.addAll(result.items);
        long scanMs = System.currentTimeMillis() - tScan0;
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("gen", gen);
            d.put("scanned", scanned.size());
            d.put("ms", scanMs);
            Debug898913Log.logAlways("MainActivity.runLibraryScanWorker",
                    "parallel scan done", "H3,H4", d);
        } catch (Exception ignored) {}
        // #endregion
        // Perf log: full scan timing is recorded after album-art ingest below.
        store.deleteExcept(seenPaths);
        reconcileCustomLibrary(scanned);
        normalizeLibraryAlbumTitles();
        // Dismiss scan overlay before slow cover ingest — art cache continues on worker thread.
        runOnUiThread(new Runnable() {
            @Override
            public void run() {
                finishLibraryScan(gen, userInitiated);
            }
        });
        // Art ingest off the scan critical path — do not block overlay dismissal.
        scheduleAlbumArtIngestAsync(gen);
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("gen", gen);
            Debug898913Log.logAlways("MainActivity.runLibraryScanWorker",
                    "scan ui finish scheduled, art async", "H5", d);
        } catch (Exception ignored) {}
        // #endregion
        ScanPerfLog.record(scanned.size(), scanMs, result.phases());
        if (libraryScanGen != gen) {
            abortLibraryScanWorker(gen);
            return;
        }
    }

    /**
     * Stop an in-flight library scan without committing partial DB deletes.
     * Bumps {@link #libraryScanGen} so the worker exits before deleteExcept / reconcile.
     */
    private void cancelLibraryScanGracefully(String reason) {
        if (!libraryScanRunning && !isCustomScanning) return;
        libraryScanGen++;
        final int cancelledGen = activeLibraryScanGen;
        abortLibraryScanWorker(cancelledGen);
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("reason", reason);
            d.put("cancelledGen", cancelledGen);
            d.put("newGen", libraryScanGen);
            DebugSessionLog.log("MainActivity.cancelLibraryScanGracefully", "scan cancelled", "H-LIB-USB", d);
        } catch (Exception ignored) {}
        // #endregion
    }

    private void applyCachedTracks(java.util.List<MusicLibraryStore.Track> cached) {
        synchronized (customLibrary) {
            customLibrary.clear();
            for (MusicLibraryStore.Track t : cached) {
                File f = new File(t.path);
                if (!f.isFile()) continue;
                if (blacklist.contains(t.path)) continue;
                customLibrary.add(songItemFromStoreTrack(t, f));
            }
        }
        invalidateSongPathIndex();
    }

    private static SongItem songItemFromStoreTrack(MusicLibraryStore.Track t, File f) {
        String genre = t.genre != null && t.genre.trim().length() > 0 ? t.genre.trim() : "Unknown Genre";
        return new SongItem(f, t.title, t.artist, t.album, genre, t.albumArtist, t.trackNumber);
    }

    private void postLibraryCacheHydrated(final int gen) {
        runOnUiThread(new Runnable() {
            @Override
            public void run() {
                if (libraryScanGen != gen) return;
                isCustomScanning = false;
                refreshLibraryBrowseIfVisible();
            }
        });
    }

    /**
     * Drop tracks whose files vanished — sync SQLite + in-memory library.
     * @return number of rows removed from {@link #customLibrary}
     */
    private int purgeStaleLibraryPaths(MusicLibraryStore store) {
        final java.util.HashSet<String> keep = MusicLibraryStore.newKeepSet();
        int pruned = 0;
        synchronized (customLibrary) {
            java.util.Iterator<SongItem> it = customLibrary.iterator();
            while (it.hasNext()) {
                SongItem song = it.next();
                if (song == null || song.file == null || !song.file.isFile()
                        || blacklist.contains(song.file.getAbsolutePath())) {
                    it.remove();
                    pruned++;
                } else {
                    keep.add(song.file.getAbsolutePath());
                }
            }
        }
        if (pruned > 0) {
            store.deleteExcept(keep);
            invalidateSongPathIndex();
            invalidateShareDurationCache();
            clearArtistOwnAlbumCache();
        }
        return pruned;
    }

    private void clearArtCacheReadyStamp() {
        if (prefs == null) return;
        prefs.edit().remove(PREF_ART_CACHE_READY_TRACKS).apply();
    }

    private void markArtCacheReadyStamp() {
        if (prefs == null) return;
        prefs.edit().putInt(PREF_ART_CACHE_READY_TRACKS, customLibrary.size()).apply();
    }

    /**
     * Skip filesystem walk when SQLite-hydrated library matches on-disk mtimes.
     * ponytail: won't detect new files until manual scan or MEDIA_MOUNTED — acceptable tradeoff.
     */
    private boolean tryFinishScanFromFreshCache(final int gen, final boolean userInitiated) {
        final MusicLibraryStore store = MusicLibraryStore.getInstance(getApplicationContext());
        purgeStaleLibraryPaths(store);
        if (customLibrary.isEmpty()) return false;
        int staleTrackCount = 0;
        int zeroTrackNumCount = 0;
        synchronized (customLibrary) {
            for (SongItem item : customLibrary) {
                if (item == null || item.file == null || !item.file.isFile()) return false;
                MusicLibraryStore.Track row = store.get(item.file.getAbsolutePath());
                if (row != null && row.trackNumber == 0) zeroTrackNumCount++;
                if (!store.isFresh(item.file)) staleTrackCount++;
            }
        }
        boolean hasGaps = albumArtCacheHasGaps();
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("gen", gen);
            d.put("userInitiated", userInitiated);
            d.put("libSize", customLibrary.size());
            d.put("staleTracks", staleTrackCount);
            d.put("zeroTrackNum", zeroTrackNumCount);
            d.put("hasGaps", hasGaps);
            d.put("artReadyStamp", prefs != null
                    ? prefs.getInt(PREF_ART_CACHE_READY_TRACKS, -1) : -1);
            Debug898913Log.logAlways("MainActivity.tryFinishScanFromFreshCache",
                    staleTrackCount == 0 ? "fast-path eligible" : "full walk required", "H1,H2", d);
        } catch (Exception ignored) {}
        // #endregion
        if (staleTrackCount > 0) return false;
        if (!hasGaps) {
            if (libraryScanGen != gen) return true;
            runOnUiThread(new Runnable() {
                @Override
                public void run() {
                    finishLibraryScan(gen, userInitiated);
                }
            });
            return true;
        }
        if (libraryScanGen != gen) return true;
        runOnUiThread(new Runnable() {
            @Override
            public void run() {
                finishLibraryScan(gen, userInitiated);
            }
        });
        scheduleAlbumArtIngestAsync(gen);
        return true;
    }

    /** Background 240px JPEG ingest — must not extend library scan worker lifetime. */
    private void scheduleAlbumArtIngestAsync(final int gen) {
        new Thread(new Runnable() {
            @Override
            public void run() {
                buildAlbumArtCacheAfterScan(gen);
            }
        }, "AlbumArtIngest").start();
    }

    /** True when any album rack cover is missing from internal AlbumArtCache. */
    private boolean albumArtCacheHasGaps() {
        if (pendingAlbumArtCacheRebuild) return true;
        if (prefs != null) {
            int readyTracks = prefs.getInt(PREF_ART_CACHE_READY_TRACKS, -1);
            if (readyTracks >= 0 && readyTracks == customLibrary.size()) return false;
        }
        if (customLibrary.isEmpty()) return false;
        File artDir = com.solar.launcher.flow.AlbumArtCache.cacheDir(getApplicationContext());
        boolean multiTrack = prefs != null && prefs.getBoolean(PREF_FLOW_MULTI_TRACK_ALBUMS, false);
        List<com.solar.launcher.flow.FlowItem> albums = com.solar.launcher.flow.FlowCatalog.buildAlbums(
                flowLibraryRows(), libraryBrowsePrefs, policyTracksFromLibrary(), multiTrack);
        for (com.solar.launcher.flow.FlowItem item : albums) {
            if (item == null || item.coverKey == null || item.coverKey.isEmpty()) continue;
            if (!com.solar.launcher.flow.AlbumArtCache.has(artDir, item.coverKey)) return true;
        }
        return false;
    }

    private void reconcileCustomLibrary(java.util.ArrayList<SongItem> scanned) {
        synchronized (customLibrary) {
            customLibrary.clear();
            customLibrary.addAll(scanned);
        }
        invalidateSongPathIndex();
        invalidateShareDurationCache();
        clearArtistOwnAlbumCache();
    }

    /** Pre-scale album art to 240px JPEG on internal storage for fast Flow navigation. */
    private void buildAlbumArtCacheAfterScan(int gen) {
        if (libraryScanGen != gen) return;
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("gen", gen);
            d.put("libSize", customLibrary.size());
            Debug898913Log.log("MainActivity.buildAlbumArtCacheAfterScan",
                    "art cache ingest start", "H1", d);
        } catch (Exception ignored) {}
        // #endregion
        final File artDir = com.solar.launcher.flow.AlbumArtCache.cacheDir(getApplicationContext());
        final File flowDir = com.solar.launcher.flow.FlowThumbCache.cacheDir(getApplicationContext());
        final com.solar.launcher.flow.FlowCoverResolver.Host host =
                new com.solar.launcher.flow.FlowCoverResolver.Host() {
            @Override public File coverFileForTrack(File track) { return MainActivity.this.coverFileForTrack(track); }
            @Override public File getCoversFolder() { return MainActivity.this.getCoversFolder(); }
            @Override public File getAlbumArtCacheDir() { return artDir; }
            @Override public File getFlowThumbCacheDir() { return flowDir; }
            @Override public android.content.SharedPreferences prefs() { return prefs; }
            @Override public android.graphics.Typeface labelFont() {
                return com.solar.launcher.theme.ThemeManager.getCustomFont();
            }
        };
        final boolean multiTrack = prefs != null && prefs.getBoolean(PREF_FLOW_MULTI_TRACK_ALBUMS, false);
        List<com.solar.launcher.flow.FlowItem> albums = com.solar.launcher.flow.FlowCatalog.buildAlbums(
                flowLibraryRows(), libraryBrowsePrefs, policyTracksFromLibrary(), multiTrack);
        long t0 = System.currentTimeMillis();
        int built = 0;
        final int albumTotal = albums.size();
        for (com.solar.launcher.flow.FlowItem item : albums) {
            if (libraryScanGen != gen) return;
            if (item == null || item.coverKey == null || item.coverKey.isEmpty()) continue;
            if (com.solar.launcher.flow.AlbumArtCache.has(artDir, item.coverKey)) {
                int flowPx = com.solar.launcher.flow.FlowThumbCache.DEFAULT_THUMB_PX;
                if (!com.solar.launcher.flow.FlowThumbCache.has(flowDir, item.coverKey, flowPx)) {
                    android.graphics.Bitmap disk =
                            com.solar.launcher.flow.AlbumArtCache.get(artDir, item.coverKey);
                    if (disk != null) {
                        com.solar.launcher.flow.FlowThumbCache.put(flowDir, item.coverKey, disk, flowPx);
                        if (!disk.isRecycled()) disk.recycle();
                    }
                }
                continue;
            }
            com.solar.launcher.flow.FlowCoverResolver.resolveFromTracks(
                    item.tracks, host, com.solar.launcher.flow.AlbumArtCache.THUMB_PX,
                    item.coverKey, artDir, flowDir);
            built++;
            if (built % 12 == 0) {
                final int done = built;
                runOnUiThread(new Runnable() {
                    @Override
                    public void run() {
                        if (libraryScanGen != gen || !libraryScanRunning) return;
                        setLoadingOverlayText(getString(R.string.library_art_cache_progress, done, albumTotal));
                    }
                });
            }
        }
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("built", built);
            d.put("albums", albums.size());
            d.put("ms", System.currentTimeMillis() - t0);
            com.solar.launcher.DebugSessionLog.log("MainActivity.buildAlbumArtCacheAfterScan",
                    "ingest complete", "H-PERF", d);
        } catch (Exception ignored) {}
        // #endregion
        markArtCacheReadyStamp();
    }

    /** Package-visible for unit tests — survives activity recreate after reset. */
    static void markPendingAlbumArtCacheRebuild() {
        pendingAlbumArtCacheRebuild = true;
    }

    static boolean consumePendingAlbumArtCacheRebuild() {
        if (!pendingAlbumArtCacheRebuild) return false;
        pendingAlbumArtCacheRebuild = false;
        return true;
    }

    /** Disk art caches were wiped — schedule rebuild when library rows still resident. */
    private void onAlbumArtCachesCleared(boolean deferUntilRecreate) {
        MusicLibraryStore.getInstance(getApplicationContext()).clearAll();
        synchronized (customLibrary) {
            customLibrary.clear();
        }
        invalidateSongPathIndex();
        clearArtCacheReadyStamp();
        libraryScanGen++;
        if (flowScreenHost != null) {
            flowScreenHost.invalidateCatalogCache();
            flowScreenHost.invalidateCoverCaches();
        }
        if (deferUntilRecreate) {
            markPendingAlbumArtCacheRebuild();
            return;
        }
        startLibraryScan(false);
    }

    /**
     * Re-ingest 240px album art JPEGs without a full library filesystem walk.
     * Used after Settings → Reset → Caches and on cold start when reset deferred rebuild.
     */
    private void scheduleAlbumArtCacheRebuild(final boolean showOverlay) {
        synchronized (customLibrary) {
            if (customLibrary.isEmpty() || albumArtCacheRebuildRunning || libraryScanRunning) {
                if (customLibrary.isEmpty()) markPendingAlbumArtCacheRebuild();
                return;
            }
        }
        albumArtCacheRebuildRunning = true;
        libraryScanGen++;
        final int gen = libraryScanGen;
        if (showOverlay) {
            runOnUiThread(new Runnable() {
                @Override
                public void run() {
                    acquireBlockingOverlay(OVERLAY_ART_CACHE,
                            getString(R.string.library_art_cache_progress, 0, 0));
                }
            });
        }
        new Thread(new Runnable() {
            @Override
            public void run() {
                buildAlbumArtCacheAfterScan(gen);
                runOnUiThread(new Runnable() {
                    @Override
                    public void run() {
                        albumArtCacheRebuildRunning = false;
                        if (libraryScanGen != gen) return;
                        if (showOverlay) releaseBlockingOverlay(OVERLAY_ART_CACHE);
                        onAlbumArtCacheRebuildFinished(gen);
                    }
                });
            }
        }, "AlbumArtRebuild").start();
    }

    /** Flow / library browse / Now Playing refresh after disk art cache ingest. */
    private void onAlbumArtCacheRebuildFinished(int gen) {
        if (flowScreenHost != null) {
            flowScreenHost.invalidateCatalogCache();
            int optionsKey = com.solar.launcher.flow.FlowCatalog.catalogOptionsKey(libraryBrowsePrefs,
                    prefs != null && prefs.getBoolean(PREF_FLOW_MULTI_TRACK_ALBUMS, false));
            flowScreenHost.precookCatalogAfterLibraryScan(gen, optionsKey);
        }
        if (currentScreenState == STATE_BROWSER) {
            clearArtistOwnAlbumCache();
            if (currentBrowserMode == BROWSER_ARTISTS) {
                buildVirtualCategories("ARTIST");
            } else if (currentBrowserMode == BROWSER_ARTIST_ALBUMS) {
                buildArtistAlbums();
            } else if (currentBrowserMode == BROWSER_VIRTUAL_SONGS) {
                buildVirtualSongs();
            } else if (currentBrowserMode == BROWSER_ALBUMS) {
                buildVirtualCategories("ALBUM");
            } else if (currentBrowserMode == BROWSER_GENRES) {
                buildVirtualCategories("GENRE");
            }
        }
        // Flow rebind runs from precookCatalogAfterLibraryScan completion — skip duplicate rebuild.
        refreshNowPlayingAlbumArtFromCache();
    }

    /** Re-bind player art from internal AlbumArtCache after cache rebuild or reset. */
    private void refreshNowPlayingAlbumArtFromCache() {
        if (!playback.isMusicActive() || playback.musicPlaylist().isEmpty()) return;
        if (lastAlbumArtBytes != null && lastAlbumArtBytes.length > 0) return;
        File track = playback.musicPlaylist().get(playback.musicIndex());
        if (track == null) return;
        String album = null;
        String artist = null;
        synchronized (customLibrary) {
            for (SongItem song : customLibrary) {
                if (song != null && song.file != null && song.file.equals(track)) {
                    album = song.album;
                    artist = song.artist;
                    break;
                }
            }
        }
        if (album == null || album.trim().isEmpty()) {
            try {
                AudioTags.Info tags = AudioTags.read(track, prefs);
                album = tags.album;
                artist = tags.artist;
            } catch (Exception ignored) {}
        }
        File sidecar = coverFileForTrack(track);
        if (sidecar != null && sidecar.isFile()) {
            applyCachedCoverArt(sidecar.getAbsolutePath());
            return;
        }
        File artDir = com.solar.launcher.flow.AlbumArtCache.cacheDir(this);
        String key = com.solar.launcher.flow.FlowCoverResolver.albumMatchKey(album, artist);
        android.graphics.Bitmap cached = com.solar.launcher.flow.AlbumArtCache.get(artDir, key);
        if (cached != null && !cached.isRecycled()) {
            bindPlayerAlbumArt(cached);
            refreshNowPlayingPreview();
            updateMainMenuBackground();
        }
    }

    private void finishLibraryScan(int gen, boolean userInitiated) {
        if (libraryScanGen != gen) return;
        libraryScanRunning = false;
        isCustomScanning = false;
        releaseBlockingOverlay(OVERLAY_LIB_SCAN);
        // #region agent log
        try {
            org.json.JSONObject d = new org.json.JSONObject();
            d.put("gen", gen);
            d.put("userInitiated", userInitiated);
            d.put("libSize", customLibrary.size());
            d.put("screen", currentScreenState);
            Debug898913Log.logAlways("MainActivity.finishLibraryScan", "scan finished", "H1", d);
        } catch (Exception ignored) {}
        // #endregion
        requestSoulseekShareRescan();
        if (soulseekActive() && soulseekSharingEnabled) {
            updateSoulseekSharePolicy();
        }
        refreshLibraryBrowseIfVisible();
        if (flowScreenHost != null) {
            int optionsKey = com.solar.launcher.flow.FlowCatalog.catalogOptionsKey(libraryBrowsePrefs,
                    prefs != null && prefs.getBoolean(PREF_FLOW_MULTI_TRACK_ALBUMS, false));
            flowScreenHost.precookCatalogAfterLibraryScan(gen, optionsKey);
        }
        if (userInitiated) {
            Toast.makeText(this,
                    "Scan Complete! " + customLibrary.size() + " songs found.", Toast.LENGTH_SHORT).show();
            refreshBrowserAfterLibraryScan();
        } else if (currentScreenState == STATE_BROWSER) {
            refreshBrowserAfterLibraryScan();
        }
    }

    private void refreshBrowserAfterLibraryScan() {
        if (currentScreenState == STATE_BROWSER) {
        if (currentBrowserMode == BROWSER_ROOT) {
            buildFileBrowserUI();
        } else if (currentBrowserMode == BROWSER_ARTISTS) {
            buildVirtualCategories("ARTIST");
        } else if (currentBrowserMode == BROWSER_ALBUMS) {
            buildVirtualCategories("ALBUM");
        } else if (currentBrowserMode == BROWSER_GENRES) {
            buildVirtualCategories("GENRE");
        } else if (currentBrowserMode == BROWSER_ARTIST_ALBUMS) {
            buildArtistAlbums();
        } else if (currentBrowserMode == BROWSER_PLAYLISTS) {
            buildPlaylistsUI();
        } else if (currentBrowserMode == BROWSER_VIRTUAL_SONGS) {
            buildVirtualSongs();
        }
        }
        // Flow rebind runs from precookCatalogAfterLibraryScan completion — skip duplicate rebuild.
    }

    private void abortLibraryScanWorker(final int gen) {
        runOnUiThread(new Runnable() {
            @Override
            public void run() {
                if (activeLibraryScanGen != gen) return;
                libraryScanRunning = false;
                isCustomScanning = false;
                releaseBlockingOverlay(OVERLAY_LIB_SCAN);
            }
        });
    }

    private void postLibraryScanProgress(final int gen, final int trackCount) {
        runOnUiThread(new Runnable() {
            @Override
            public void run() {
                if (libraryScanGen != gen || !libraryScanRunning) return;
                if ((blockingOverlayOwners & OVERLAY_LIB_SCAN) == 0) return;
                updateBlockingOverlayText(getString(R.string.library_scan_progress, trackCount));
            }
        });
    }

    private LibraryScanResolved resolveSongItemForScan(File f, MusicLibraryStore store, int gen) {
        try {
            if (libraryScanGen != gen) return null;
            String title;
            String artist;
            String album;
            String genre;
            String albumArtist;
            String durationMs;
            int trackNumber = 0;
            MusicLibraryStore.Track cached = store.getFresh(f);
            if (cached != null) {
                title = cached.title;
                artist = cached.artist;
                album = cached.album;
                genre = cached.genre;
                albumArtist = cached.albumArtist;
                durationMs = cached.durationMs;
                trackNumber = cached.trackNumber;
            } else {
                if (libraryScanGen != gen) return null;
                AudioTags.Info tags = AudioTags.read(f, prefs, AudioTags.READ_SKIP_EMBEDDED_ART);
                title = tags.title;
                artist = tags.artist;
                album = tags.album;
                genre = tags.genre;
                albumArtist = tags.albumArtist;
                durationMs = tags.durationMs;
                trackNumber = tags.trackNumber;
                if (artist.isEmpty()) artist = "Unknown Artist";
                if (album.isEmpty()) album = "Unknown Album";
                store.upsert(f, title, artist, album, genre, albumArtist, durationMs, trackNumber);
            }
            LibraryScanResolved resolved = new LibraryScanResolved();
            resolved.item = songItemFromStoreTrack(
                    new MusicLibraryStore.Track(f.getAbsolutePath(), f.lastModified(), f.length(),
                            title, artist, album, genre, albumArtist, durationMs, trackNumber),
                    f);
            resolved.metaKey = (title + "\0" + artist + "\0" + durationMs)
                    .toLowerCase(java.util.Locale.US);
            return resolved;
        } catch (Exception e) {
            return null;
        }
    }

    /** Merge album tags that differ only by letter case (majority spelling wins). */
    private void normalizeLibraryAlbumTitles() {
        if (libraryBrowsePrefs == null || !libraryBrowsePrefs.normalizeAlbumCase()) return;
        java.util.ArrayList<String> rawAlbums = new java.util.ArrayList<>();
        for (SongItem song : customLibrary) {
            if (song.album != null && !song.album.trim().isEmpty()) rawAlbums.add(song.album);
        }
        java.util.Map<String, String> canonicalByKey = AlbumNames.canonicalTitles(rawAlbums);
        if (canonicalByKey.isEmpty()) return;
        for (SongItem song : customLibrary) {
            song.album = AlbumNames.normalizeDisplay(song.album, canonicalByKey);
        }
        clearArtistOwnAlbumCache();
    }

    // 💡 2. 라이브러리 메인 라우터 (자체 스캔 버튼 적용)
    private void updateLibraryBreadcrumb() {
        if (tvBrowserPath == null || currentScreenState != STATE_BROWSER) return;
        tvBrowserPath.setText(buildLibraryBreadcrumb());
        tvBrowserPath.setVisibility(View.VISIBLE);
    }

    private void refreshBrowserPathBreadcrumb() {
        if (tvBrowserPath == null) return;
        if (currentScreenState == STATE_BROWSER) {
            updateLibraryBreadcrumb();
        } else if (currentScreenState == STATE_PODCASTS || currentScreenState == STATE_SOULSEEK) {
            tvBrowserPath.setVisibility(View.VISIBLE);
        } else if (currentScreenState == STATE_APPS) {
            tvBrowserPath.setText(getString(R.string.path_apps));
            tvBrowserPath.setVisibility(View.VISIBLE);
        } else {
            tvBrowserPath.setVisibility(View.GONE);
        }
    }

    private String buildLibraryBreadcrumb() {
        if (isPickingBackground) {
            String pathLabel = currentFolder.getAbsolutePath().replace("/storage/sdcard0", "");
            if (pathLabel.isEmpty()) pathLabel = "/";
            return getString(R.string.path_library_pick_image, pathLabel);
        }
        switch (currentBrowserMode) {
            case BROWSER_FOLDER: {
                String pathLabel = currentFolder.getAbsolutePath().replace("/storage/sdcard0", "");
                if (pathLabel.isEmpty()) pathLabel = "/";
                return getString(R.string.path_library_folders, pathLabel);
            }
            case BROWSER_ARTISTS:
                return getString(R.string.path_library_artists);
            case BROWSER_ARTIST_ALBUMS:
                return getString(R.string.path_library_artist_albums, virtualQueryArtist);
            case BROWSER_ALBUMS:
                return getString(R.string.path_library_albums);
            case BROWSER_GENRES:
                return getString(R.string.path_library_genres);
            case BROWSER_PLAYLISTS:
                return getString(R.string.path_library_playlists);
            case BROWSER_DEEZER_PLAYLIST:
                return deezerPlaylistView != null
                        ? getString(R.string.path_library_playlist, deezerPlaylistView.title)
                        : getString(R.string.path_library_playlists);
            case BROWSER_VIRTUAL_SONGS:
                if ("ALL".equals(virtualQueryType)) return getString(R.string.path_library_all_songs);
                if ("ARTIST_ALBUM".equals(virtualQueryType)) {
                    return getString(R.string.path_library_artist_album_tracks, virtualQueryArtist, virtualQueryValue);
                }
                if ("ARTIST".equals(virtualQueryType)) return getString(R.string.path_library_artist, virtualQueryValue);
                if ("ALBUM".equals(virtualQueryType)) return getString(R.string.path_library_album, virtualQueryValue);
                if ("GENRE".equals(virtualQueryType)) return getString(R.string.path_library_genre, virtualQueryValue);
                if ("PLAYLIST".equals(virtualQueryType)) return getString(R.string.path_library_playlist, virtualQueryValue);
                return getString(R.string.path_library_section, virtualQueryValue);
            default:
                return getString(R.string.path_library_root);
        }
    }

    /** True when the visible list is tracks inside one album (not a mixed song list). */
    private boolean isLibraryAlbumTrackSortContext() {
        return currentBrowserMode == BROWSER_VIRTUAL_SONGS
                && ("ALBUM".equals(virtualQueryType) || "ARTIST_ALBUM".equals(virtualQueryType));
    }

    private String librarySortLabel() {
        boolean albumTracks = isLibraryAlbumTrackSortContext();
        int sort = albumTracks ? libraryBrowsePrefs.albumSongSort() : libraryBrowsePrefs.songSort();
        return getString(LibraryBrowsePrefs.songSortLabelRes(sort, albumTracks));
    }

    private void cycleLibrarySort() {
        boolean albumTracks = isLibraryAlbumTrackSortContext();
        if (albumTracks) {
            libraryBrowsePrefs.cycleAlbumSongSort();
        } else {
            libraryBrowsePrefs.cycleSongSort();
        }
        Toast.makeText(this, getString(R.string.library_sort_now, librarySortLabel()), Toast.LENGTH_SHORT).show();
        if (currentBrowserMode == BROWSER_VIRTUAL_SONGS) buildVirtualSongs();
    }

    private static int compareAlphanumeric(String s1, String s2) {
        int i1 = 0, i2 = 0;
        while (i1 < s1.length() && i2 < s2.length()) {
            char c1 = s1.charAt(i1);
            char c2 = s2.charAt(i2);
            if (Character.isDigit(c1) && Character.isDigit(c2)) {
                long n1 = 0, n2 = 0;
                while (i1 < s1.length() && Character.isDigit(s1.charAt(i1))) {
                    n1 = n1 * 10 + (s1.charAt(i1) - '0');
                    i1++;
                }
                while (i2 < s2.length() && Character.isDigit(s2.charAt(i2))) {
                    n2 = n2 * 10 + (s2.charAt(i2) - '0');
                    i2++;
                }
                if (n1 != n2) return Long.compare(n1, n2);
            } else {
                int c = Character.toLowerCase(c1) - Character.toLowerCase(c2);
                if (c != 0) return c;
                i1++; i2++;
            }
        }
        return s1.length() - s2.length();
    }

    private void sortSongItems(List<SongItem> list, boolean isAlbumContext) {
        int sortMode = isAlbumContext ? libraryBrowsePrefs.albumSongSort() : libraryBrowsePrefs.songSort();
        final int finalSortMode = sortMode;
        java.util.Collections.sort(list, new java.util.Comparator<SongItem>() {
            @Override
            public int compare(SongItem a, SongItem b) {
                switch (finalSortMode) {
                    case LibraryBrowsePrefs.SONG_SORT_ARTIST:
                        int c = a.artist.compareToIgnoreCase(b.artist);
                        if (c != 0) return c;
                        return compareAlphanumeric(a.file.getName(), b.file.getName());
                    case LibraryBrowsePrefs.SONG_SORT_ALBUM:
                        c = a.album.compareToIgnoreCase(b.album);
                        if (c != 0) return c;
                        if (a.trackNumber != b.trackNumber) {
                            return Integer.compare(a.trackNumber, b.trackNumber);
                        }
                        return compareAlphanumeric(a.file.getName(), b.file.getName());
                    case LibraryBrowsePrefs.SONG_SORT_DATE:
                        long da = a.file.lastModified();
                        long db = b.file.lastModified();
                        return da == db ? compareAlphanumeric(a.file.getName(), b.file.getName()) : Long.compare(db, da);
                    default:
                        return a.title.compareToIgnoreCase(b.title);
                }
            }
        });
    }

